//#region domain/consoleBoundary.js
// @requires (none)
function okBoundary(value) {
  return Object.freeze({ ok: true, value });
}

function errorBoundary(code, message) {
  return Object.freeze({ ok: false, error: Object.freeze({ code, message }) });
}

function isObjectLike(value) {
  return value !== null && typeof value === 'object' && !Array.isArray(value);
}

function cloneBoundaryValue(value) {
  if (value === null || typeof value !== 'object') return value;
  return JSON.parse(JSON.stringify(value));
}

function normalizeSessionPayload(payload) {
  if (!isObjectLike(payload)) {
    return errorBoundary('invalid_session_payload', 'Session payload must be an object.');
  }
  const sessionId = String(payload.sessionId || '').trim();
  if (!sessionId) {
    return errorBoundary('missing_session_id', 'Session payload is missing sessionId.');
  }
  return okBoundary(Object.freeze({
    ...cloneBoundaryValue(payload),
    sessionId,
    items: Array.isArray(payload.items) ? cloneBoundaryValue(payload.items) : [],
    screens: Array.isArray(payload.screens) ? cloneBoundaryValue(payload.screens) : [],
  }));
}

function normalizePreviewPayload(payload) {
  if (!isObjectLike(payload)) {
    return errorBoundary('invalid_preview_payload', 'Preview payload must be an object.');
  }
  const previewId = String(payload.previewId || '').trim();
  const screen = isObjectLike(payload.screen) ? payload.screen : null;
  const screenId = String(screen?.screenId || payload.screenId || '').trim();
  if (!previewId) {
    return errorBoundary('missing_preview_id', 'Preview payload is missing previewId.');
  }
  if (!screenId) {
    return errorBoundary('missing_screen_id', 'Preview payload is missing screenId.');
  }
  return okBoundary(Object.freeze({
    ...cloneBoundaryValue(payload),
    previewId,
    screen: Object.freeze({ ...cloneBoundaryValue(screen || {}), screenId }),
  }));
}

function normalizeDraftItemPayload(payload) {
  if (!isObjectLike(payload)) {
    return errorBoundary('invalid_draft_item', 'Draft item payload must be an object.');
  }
  const itemId = String(payload.itemId || payload.annotationId || '').trim();
  if (!itemId) {
    return errorBoundary('missing_item_id', 'Draft item payload is missing itemId.');
  }
  return okBoundary(Object.freeze({
    ...cloneBoundaryValue(payload),
    itemId,
    annotationId: String(payload.annotationId || itemId),
    comment: String(payload.comment || ''),
    selection: cloneBoundaryValue(payload.selection || null),
    targetEvidence: cloneBoundaryValue(payload.targetEvidence || null),
  }));
}

function normalizeStoredJson(text) {
  if (!text) return okBoundary(null);
  try {
    return okBoundary(JSON.parse(text));
  } catch (_) {
    return errorBoundary('invalid_storage_payload', 'Storage payload is not valid JSON.');
  }
}
//#endregion domain/consoleBoundary.js

//#region draftStorageAdapter.js
// @requires draftPorts.js, draftWorkspace.js, domain/consoleBoundary.js
// draftStorageAdapter.js - browser storage adapter for DraftWorkspace recovery.

const DraftWorkspaceKeyPrefix = 'fixthis.workspace.';

function draftWorkspaceKey(sessionId, workspaceId) {
  return DraftWorkspaceKeyPrefix + sessionId + '.' + workspaceId;
}

function draftWorkspaceIndexKey(sessionId) {
  return DraftWorkspaceKeyPrefix + 'index.' + sessionId;
}

function parseDraftStorageJson(raw) {
  if (!raw) return null;
  try { return JSON.parse(raw); } catch (_) { return null; }
}

function dropEmptyEntries(envelope) {
  if (!envelope) return { items: [] };
  let dropped = 0;
  const items = (envelope.items || []).filter((item) => {
    const comment = String(item?.comment || '');
    if (comment.length === 0) {
      dropped += 1;
      return false;
    }
    return true;
  });
  if (dropped > 0) {
    console.info(`[draft-recovery] skipped ${dropped} empty-comment entries`);
  }
  return { ...envelope, items };
}

function createDraftStorageAdapter(localStorageLike) {
  function readIndex(sessionId) {
    const parsed = parseDraftStorageJson(localStorageLike.getItem(draftWorkspaceIndexKey(sessionId)));
    return Array.isArray(parsed) ? parsed : [];
  }

  function writeIndex(sessionId, workspaceIds) {
    localStorageLike.setItem(draftWorkspaceIndexKey(sessionId), JSON.stringify(Array.from(new Set(workspaceIds))));
  }

  function saveWorkspace(envelope) {
    const sessionId = envelope?.sessionId || envelope?.context?.sessionId;
    const workspaceId = envelope?.workspaceId;
    if (!sessionId || !workspaceId) throw new Error('Workspace storage requires sessionId and workspaceId');
    const normalized = { ...envelope, schemaVersion: 2, sessionId, workspaceId };
    localStorageLike.setItem(draftWorkspaceKey(sessionId, workspaceId), JSON.stringify(normalized));
    writeIndex(sessionId, readIndex(sessionId).concat(workspaceId));
  }

  function loadWorkspacesForSession(sessionId) {
    return readIndex(sessionId)
      .map((workspaceId) => {
        const key = draftWorkspaceKey(sessionId, workspaceId);
        const parsed = normalizeStoredJson(localStorageLike.getItem(key));
        if (!parsed.ok) {
          localStorageLike.removeItem(key);
          return null;
        }
        const filtered = dropEmptyEntries(parsed.value);
        if (!filtered.items.length) {
          localStorageLike.removeItem(key);
          return null;
        }
        return filtered;
      })
      .filter((value) => value?.schemaVersion === 2 && value?.context?.sessionId === sessionId);
  }

  function deleteWorkspace(sessionId, workspaceId) {
    localStorageLike.removeItem(draftWorkspaceKey(sessionId, workspaceId));
    writeIndex(sessionId, readIndex(sessionId).filter((id) => id !== workspaceId));
  }

  function deleteWorkspacesForSession(sessionId) {
    if (!sessionId) return;
    readIndex(sessionId).forEach((workspaceId) => {
      localStorageLike.removeItem(draftWorkspaceKey(sessionId, workspaceId));
    });
    localStorageLike.removeItem(draftWorkspaceIndexKey(sessionId));
  }

  return {
    saveWorkspace,
    loadWorkspacesForSession,
    deleteWorkspace,
    deleteWorkspacesForSession,
  };
}
//#endregion draftStorageAdapter.js

//#region adapters/browserPorts.js
// @requires draftStorageAdapter.js
function createBrowserConsolePorts(options = {}) {
  const requestJson_ = options.requestJson;
  const localStorage_ = options.localStorage || localStorage;
  return Object.freeze({
    sessionApi: Object.freeze({
      openSession: async (sessionId) => requestJson_('/api/session/open', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ sessionId }),
      }),
      listSessions: async () => requestJson_('/api/sessions'),
      currentSession: async () => requestJson_('/api/session'),
      saveDraft: async () => {
        throw new Error('Canonical saveDraft effect is disabled until DraftWorkspace save request construction is canonical.');
      },
    }),
    previewApi: Object.freeze({
      capturePreview: async () => requestJson_('/api/preview'),
    }),
    draftStorage: Object.freeze({
      saveRecovery: async (sessionId, workspace) => {
        const adapter = createDraftStorageAdapter(localStorage_);
        adapter.saveWorkspace({
          ...workspace,
          schemaVersion: 2,
          sessionId: sessionId || workspace?.context?.sessionId,
          workspaceId: workspace?.workspaceId || workspace?.context?.workspaceId,
        });
      },
      deleteRecovery: async (sessionId, workspaceId) => {
        const adapter = createDraftStorageAdapter(localStorage_);
        adapter.deleteWorkspace(sessionId, workspaceId);
      },
    }),
    clipboard: Object.freeze({
      writeText: async (text) => navigator.clipboard.writeText(text),
    }),
    timer: Object.freeze({
      setTimeout: (callback, delayMs) => setTimeout(callback, delayMs),
      clearTimeout: (id) => clearTimeout(id),
    }),
    clock: Object.freeze({ now: () => Date.now() }),
  });
}
//#endregion adapters/browserPorts.js

//#region domain/workspaceState.js
// @requires (none)
const WorkspaceKind = Object.freeze({
  EMPTY: 'empty',
  LIVE_PREVIEW: 'livePreview',
  DRAFT: 'draft',
  SAVED_FOCUS: 'savedFocus',
  RECOVERY: 'recovery',
});

function emptyWorkspace() {
  return Object.freeze({ kind: WorkspaceKind.EMPTY });
}

function livePreviewWorkspace(sessionId, preview = null) {
  return Object.freeze({
    kind: WorkspaceKind.LIVE_PREVIEW,
    sessionId: sessionId || null,
    preview: cloneConsoleValue(preview),
  });
}

function draftWorkspaceFromPreview(sessionId, preview, options = {}) {
  if (!sessionId) throw new Error('Draft workspace requires sessionId');
  if (!preview?.previewId) throw new Error('Draft workspace requires previewId');
  const screen = preview.screen || null;
  if (!screen?.screenId) throw new Error('Draft workspace requires screenId');
  return Object.freeze({
    kind: WorkspaceKind.DRAFT,
    context: Object.freeze({
      sessionId,
      previewId: preview.previewId,
      screenId: screen.screenId,
      screenFingerprint: screen.fingerprint ?? null,
      deviceSerial: options.deviceSerial || null,
      frozenAtEpochMillis: preview.frozenAtEpochMillis || options.frozenAtEpochMillis || null,
      activityName: preview.activity || options.activityName || null,
      workspaceId: options.workspaceId || `draft-${sessionId}-${preview.previewId}`,
    }),
    screen: cloneConsoleValue(screen),
    screenshotUrl: preview.screenshotUrl || options.screenshotUrl || '',
    items: Object.freeze([...(options.items || [])].map(cloneConsoleValue)),
    focusedItemId: options.focusedItemId || null,
    currentSelection: cloneConsoleValue(options.currentSelection || null),
    activityDriftWarning: cloneConsoleValue(options.activityDriftWarning || null),
  });
}

function draftWorkspaceWithPatch(workspace, patch = {}) {
  if (!isDraftWorkspace(workspace)) return workspace;
  return Object.freeze({
    ...workspace,
    ...patch,
    context: Object.freeze({ ...workspace.context, ...(patch.context || {}) }),
    items: Object.freeze([...(patch.items || workspace.items || [])].map(cloneConsoleValue)),
  });
}

function savedFocusWorkspace(sessionId, screenId, itemId = null) {
  return Object.freeze({
    kind: WorkspaceKind.SAVED_FOCUS,
    sessionId: sessionId || null,
    screenId: screenId || null,
    itemId: itemId || null,
  });
}

function recoveryWorkspace(sessionId, recovery) {
  return Object.freeze({
    kind: WorkspaceKind.RECOVERY,
    sessionId: sessionId || null,
    recovery: cloneConsoleValue(recovery),
  });
}

function isDraftWorkspace(workspace) {
  return workspace?.kind === WorkspaceKind.DRAFT;
}

function cloneConsoleValue(value) {
  if (value == null) return value;
  return JSON.parse(JSON.stringify(value));
}
//#endregion domain/workspaceState.js

//#region domain/consoleSelectors.js
// @requires domain/workspaceState.js
function selectHistoryModel(state) {
  return Object.freeze({
    activeSessionId: state.activeSessionId,
    sessionIds: Object.freeze([...state.sessionOrder]),
    sessionsById: Object.freeze({ ...state.sessionsById }),
    workspaceKind: state.workspace.kind,
    draftSessionId: state.workspace.kind === WorkspaceKind.DRAFT ? state.workspace.context.sessionId : null,
    draftBadges: state.workspace.kind === WorkspaceKind.DRAFT
      ? Object.freeze([`${state.workspace.items.length} draft pins`, 'live paused'])
      : Object.freeze([]),
    pendingBoundary: state.pendingBoundary,
  });
}

function selectInspectorModel(state) {
  const workspace = state.workspace;
  if (workspace.kind === WorkspaceKind.DRAFT) {
    return Object.freeze({
      mode: 'draft',
      title: 'Draft Annotations',
      count: workspace.items.length,
      rows: Object.freeze([...workspace.items]),
      primaryAction: null,
      secondaryAction: null,
    });
  }
  if (workspace.kind === WorkspaceKind.RECOVERY) {
    return Object.freeze({
      mode: 'recovery',
      title: 'Recovered Draft',
      count: 0,
      rows: Object.freeze([]),
      primaryAction: Object.freeze({ label: 'Recover', type: 'RECOVERY_RECOVER_CLICKED' }),
      secondaryAction: Object.freeze({ label: 'Discard', type: 'RECOVERY_DISCARD_CLICKED' }),
    });
  }
  if (workspace.kind === WorkspaceKind.SAVED_FOCUS) {
    return Object.freeze({
      mode: 'saved',
      title: 'Saved Annotations',
      count: 0,
      rows: Object.freeze([]),
      primaryAction: null,
      secondaryAction: null,
    });
  }
  return Object.freeze({
    mode: 'empty',
    title: 'Annotations',
    count: 0,
    rows: Object.freeze([]),
    primaryAction: Object.freeze({ label: 'Start annotating', type: 'ANNOTATE_CLICKED' }),
    secondaryAction: null,
  });
}

function selectCanvasModel(state) {
  const workspace = state.workspace;
  if (workspace.kind === WorkspaceKind.DRAFT) {
    return Object.freeze({
      mode: 'frozenDraft',
      sessionId: workspace.context.sessionId,
      screen: workspace.screen,
      screenshotUrl: workspace.screenshotUrl,
      pins: Object.freeze([...workspace.items]),
      lockLabel: 'Locked: Session ' + workspace.context.sessionId + ' · Preview ' + workspace.context.previewId,
    });
  }
  if (workspace.kind === WorkspaceKind.LIVE_PREVIEW) {
    return Object.freeze({ mode: 'livePreview', sessionId: workspace.sessionId, preview: workspace.preview });
  }
  if (workspace.kind === WorkspaceKind.SAVED_FOCUS) {
    return Object.freeze({ mode: 'savedFocus', sessionId: workspace.sessionId, screenId: workspace.screenId, itemId: workspace.itemId });
  }
  if (workspace.kind === WorkspaceKind.RECOVERY) {
    return Object.freeze({ mode: 'recovery', sessionId: workspace.sessionId, recovery: workspace.recovery });
  }
  return Object.freeze({ mode: 'empty' });
}

function selectBoundarySheet(state) {
  if (!state.pendingBoundary) return null;
  return Object.freeze({
    kind: state.pendingBoundary.kind,
    title: 'Switch to ' + state.pendingBoundary.targetSessionId + '?',
    fromSessionId: state.pendingBoundary.fromSessionId,
    targetSessionId: state.pendingBoundary.targetSessionId,
    draftSummary: state.pendingBoundary.draftSummary,
    actions: Object.freeze([
      Object.freeze({ label: 'Save draft', type: 'BOUNDARY_SAVE_DRAFT_CLICKED' }),
      Object.freeze({ label: 'Keep in recovery', type: 'BOUNDARY_KEEP_RECOVERY_CLICKED' }),
      Object.freeze({ label: 'Discard', type: 'BOUNDARY_DISCARD_CLICKED' }),
      Object.freeze({ label: 'Cancel', type: 'BOUNDARY_CANCEL_CLICKED' }),
    ]),
  });
}

function selectPromptReadiness(state) {
  const workspace = state.workspace;
  if (workspace.kind !== WorkspaceKind.DRAFT || workspace.items.length === 0) {
    return Object.freeze({ state: 'empty', label: 'No annotations ready', disabled: true });
  }
  const missing = workspace.items.filter((item) => !String(item.comment || '').trim()).length;
  if (missing) {
    return Object.freeze({
      state: 'blocked',
      label: workspace.items.length + ' drafts · ' + missing + ' missing comment',
      disabled: true,
    });
  }
  return Object.freeze({ state: 'ready', label: workspace.items.length + ' drafts ready', disabled: false });
}

function selectDraftLockModel(state) {
  if (!isDraftWorkspace(state.workspace)) return Object.freeze({ visible: false });
  return Object.freeze({
    visible: true,
    sessionId: state.workspace.context.sessionId,
    previewId: state.workspace.context.previewId,
    screenId: state.workspace.context.screenId,
    itemCount: state.workspace.items.length,
    missingCommentCount: state.workspace.items.filter((item) => !String(item.comment || '').trim()).length,
    frozenAtEpochMillis: state.workspace.context.frozenAtEpochMillis || null,
  });
}

function selectToolbarModel(state) {
  const draft = isDraftWorkspace(state.workspace);
  return Object.freeze({
    activeSessionId: state.activeSessionId,
    previewLocked: draft,
    canAnnotate: Boolean(state.activeSessionId) && !draft,
    canSave: draft && state.workspace.items.length > 0 && !state.promptAction.inFlight,
    canCopy: draft && state.workspace.items.length > 0 && !state.promptAction.inFlight,
  });
}
