//#region annotationCollections.js
// @requires state.js
            // Display-side annotations for the toolbar counter and the right Annotations panel.
            // Includes already-sent items so the count matches the sidebar Session card's lifetime total
            // (sidebar uses server-side unresolvedItemsCount, which counts by status only - not delivery).
            // The send/copy path uses currentPromptAnnotations(), which re-applies the delivery filter
            // so already-sent items are not re-sent.
            function toolbarAnnotations() {
              if (draftFlow()) return draftItemList();
              return state.session?.items || [];
            }

            function hasWrittenAnnotationComment(item) {
              return Boolean(String(item?.comment || '').trim());
            }

            function draftItemsFromValue(value) {
              if (Array.isArray(value)) return value;
              return Array.isArray(value?.items) ? value.items : [];
            }

            function commentedDraftItems(value) {
              return draftItemsFromValue(value).filter(hasWrittenAnnotationComment);
            }

            function pinOnlyDraftItems(value) {
              return draftItemsFromValue(value).filter(item => !hasWrittenAnnotationComment(item));
            }

            function draftRecoverySummary(value) {
              const items = draftItemsFromValue(value);
              const commented = commentedDraftItems(items);
              const pinOnly = pinOnlyDraftItems(items);
              return {
                total: items.length,
                commented: commented.length,
                pinOnly: pinOnly.length,
              };
            }

            function hasCommentedDraftItems(value) {
              return draftRecoverySummary(value).commented > 0;
            }

            function currentPromptAnnotations() {
              if (!state.session) return [];
              return toolbarAnnotations()
                .filter(item => item.delivery !== 'sent')
                .filter(hasWrittenAnnotationComment);
            }
//#endregion annotationCollections.js

//#region api.js
// @requires state.js
            class ConsoleRequestError extends Error {
              constructor({ status, error, message, action, details, bodyText }) {
                super(message || error || bodyText || ('HTTP ' + status));
                this.name = 'ConsoleRequestError';
                this.status = status;
                this.error = error || null;
                this.action = action || null;
                this.details = details || {};
                this.bodyText = bodyText || '';
              }
            }

            function responseContentType(response) {
              if (!response?.headers) return '';
              if (typeof response.headers.get === 'function') return response.headers.get('content-type') || '';
              if (typeof response.headers.get === 'undefined' && typeof response.headers[Symbol.iterator] === 'function') {
                for (const [key, value] of response.headers) {
                  if (String(key).toLowerCase() === 'content-type') return String(value);
                }
              }
              return '';
            }

            async function readStructuredError(response) {
              const bodyText = await response.text();
              const contentType = responseContentType(response);
              if (contentType.includes('application/json') || bodyText.trim().startsWith('{')) {
                try {
                  const parsed = JSON.parse(bodyText);
                  return new ConsoleRequestError({
                    status: response.status,
                    error: parsed.error,
                    message: parsed.message,
                    action: parsed.action,
                    details: parsed.details,
                    bodyText,
                  });
                } catch (_) {
                  return new ConsoleRequestError({ status: response.status, bodyText });
                }
              }
              return new ConsoleRequestError({ status: response.status, bodyText });
            }

            async function requestJson(path, options = {}) {
              const method = (options.method || 'GET').toUpperCase();
              const headers = new Headers(options.headers || {});
              if (['POST', 'PUT', 'PATCH', 'DELETE'].includes(method)) {
                const token = window.FixThisConsoleConfig?.consoleToken;
                if (token) headers.set('X-FixThis-Console-Token', token);
              }
              const response = await fetch(path, { ...options, headers });
              if (!response.ok) {
                const err = await readStructuredError(response);
                // Spec S1.4.1: fire the reload_console banner before propagating.
                if (typeof surfaceReloadConsoleNotice === 'function') surfaceReloadConsoleNotice(err);
                throw err;
              }
              return response.json();
            }

            async function copyTextToClipboard(text) {
              try {
                if (navigator.clipboard?.writeText) {
                  await navigator.clipboard.writeText(text);
                  return;
                }
              } catch (cause) {
                // Fall back below for browser surfaces that deny Clipboard API writes.
              }
              const fallback = document.createElement('textarea');
              fallback.value = text;
              fallback.setAttribute('readonly', '');
              fallback.style.position = 'fixed';
              fallback.style.top = '-9999px';
              fallback.style.left = '-9999px';
              document.body.appendChild(fallback);
              fallback.focus();
              fallback.select();
              const copied = document.execCommand('copy');
              fallback.remove();
              if (!copied) throw new Error('Copy failed. Select the prompt and copy it manually.');
            }
//#endregion api.js

//#region connection.js
// @requires state.js, api.js
            // Heartbeat timer handles. These are connection-internal browser
            // timer state (not reducer state, not pure) so they live here
            // rather than in connectionFsm.js or state.js.
            let heartbeatTimer = null;
            let heartbeatPolling = false;
            const LaunchConnectionRefreshDelaysMs = Object.freeze([800, 1200, 2000, 3000, 5000]);
            let launchRefreshTimer = null;

            function connectionActionLabel(action) {
              if (action === 'START') return 'Start';
              if (action === 'OPEN_APP') return 'Open app';
              if (action === 'RECONNECT') return 'Reconnect';
              if (action === 'TRY_AGAIN') return 'Try again';
              if (action === 'CHOOSE_DEVICE') return 'Choose device';
              if (action === 'CAPTURE') return 'Capture screen';
              return 'Continue';
            }

            function connectionActionAccessibleLabel(action) {
              if (action === 'START') return 'Start FixThis connection';
              if (action === 'OPEN_APP') return 'Open debug app';
              if (action === 'RECONNECT') return 'Reconnect to debug app';
              if (action === 'TRY_AGAIN') return 'Retry connection';
              if (action === 'CHOOSE_DEVICE') return 'Choose Android device';
              if (action === 'CAPTURE') return 'Capture screen';
              return connectionActionLabel(action);
            }

            function userConnectionState(status) {
              if (!status) return 'welcome';
              const rawState = String(status.state || 'WELCOME').toLowerCase();
              if (rawState === 'open_app' && connectionUseCases.getState().hasEverConnected) return 'reconnect';
              return rawState;
            }

            function shouldContinueLaunchConnectionRefresh(status) {
              const rawState = String(status?.state || '').toLowerCase();
              return rawState === 'starting' || rawState === 'open_app' || rawState === 'reconnect';
            }

            function clearLaunchConnectionRefresh() {
              if (launchRefreshTimer) clearTimeout(launchRefreshTimer);
              launchRefreshTimer = null;
            }

            function scheduleLaunchConnectionRefresh(attempt = 0) {
              clearLaunchConnectionRefresh();
              const currentStatus = connectionUseCases.getState().current;
              if (!shouldContinueLaunchConnectionRefresh(currentStatus)) return;
              if (attempt >= LaunchConnectionRefreshDelaysMs.length) return;
              const delayMs = LaunchConnectionRefreshDelaysMs[attempt];
              launchRefreshTimer = setTimeout(() => {
                launchRefreshTimer = null;
                refreshConnection({ preservePreviewStale: true })
                  .then((status) => {
                    if (!status) {
                      scheduleLaunchConnectionRefresh(attempt + 1);
                      return;
                    }
                    if (userConnectionState(status) === 'ready') {
                      if (state.session && !draftFlow()) refreshPreview().catch(showError);
                      return;
                    }
                    if (shouldContinueLaunchConnectionRefresh(status)) {
                      scheduleLaunchConnectionRefresh(attempt + 1);
                    }
                  })
                  .catch((cause) => {
                    console.warn('[fixthis] launch connection refresh failed:', cause);
                    scheduleLaunchConnectionRefresh(attempt + 1);
                  });
              }, delayMs);
            }

            function connectionDetailsText(status) {
              if (!status) return 'No connection check has run yet.';
              const details = status.details || {};
              const connectionState = connectionUseCases.getState();
              return [
                'Device: ' + (status.selectedDevice ? deviceLabel(status.selectedDevice) + ' - ' + text(status.selectedDevice.state) : 'none'),
                'Package: ' + text(status.packageName),
                'Bridge: ' + text(details.bridgeState),
                'Last connected: ' + (connectionState.lastReadyAt ? new Date(connectionState.lastReadyAt).toLocaleTimeString() : '-'),
                'Raw error: ' + text(details.rawError)
              ].join('\n');
            }

            function markPreviewStale(stale) {
              const hasPreviewSurface = Boolean(state.preview || draftFlow()?.screen || latestPersistedScreen());
              if (stale && hasPreviewSurface) {
                statusSurfaceRegistry.show('previewStaleBadge', {
                  surfaceClass: 'badge',
                  priority: 3,
                  element: previewStaleBadge,
                  content: 'Connection paused - showing last preview',
                });
              } else {
                statusSurfaceRegistry.hide('previewStaleBadge');
              }
            }

            function applyDisconnect({ hasDirtyDraft = false } = {}) {
              const overlay = document.getElementById('canvasBlockedOverlay');
              if (overlay) {
                statusSurfaceRegistry.show('canvasBlockedOverlay', {
                  surfaceClass: 'modalCanvas',
                  priority: 1,
                  element: overlay,
                  content: {
                    headline: 'Device disconnected',
                    detail: 'Reconnecting...',
                    retry: true,
                  },
                });
              }
              statusSurfaceRegistry.hide('canvasStaleNotice');
              statusSurfaceRegistry.hide('previewStaleBadge');
              const banner = document.getElementById('stalenessBanner');
              if (hasDirtyDraft && banner) {
                statusSurfaceRegistry.show('stalenessBanner', {
                  surfaceClass: 'banner',
                  priority: 2,
                  element: banner,
                  content: '1 unsaved draft preserved locally',
                });
              } else {
                statusSurfaceRegistry.hide('stalenessBanner');
              }
            }

            function applyReconnect({ targetStale = false } = {}) {
              statusSurfaceRegistry.hide('canvasBlockedOverlay');
              if (targetStale) {
                const notice = document.getElementById('canvasStaleNotice');
                if (notice) {
                  const title = notice.querySelector('[data-stale-title]');
                  const detail = notice.querySelector('[data-stale-detail]');
                  if (title) title.textContent = 'Recovered draft';
                  if (detail) detail.textContent = 'Live preview paused for this frozen frame.';
                  statusSurfaceRegistry.show('canvasStaleNotice', {
                    surfaceClass: 'inline',
                    priority: 3,
                    element: notice,
                  });
                }
                statusSurfaceRegistry.hide('previewStaleBadge');
                return;
              }
              statusSurfaceRegistry.hide('canvasStaleNotice');
              const badge = document.getElementById('previewStaleBadge');
              if (badge) {
                statusSurfaceRegistry.show('previewStaleBadge', {
                  surfaceClass: 'badge',
                  priority: 3,
                  element: badge,
                  content: 'Connection restored - refreshing preview',
                  autoDismissMs: 2000,
                });
              }
            }

            function shouldShowDisconnectChoreography(viewState) {
              return viewState === 'check_phone' || viewState === 'reconnect';
            }

            function syncSelectedDeviceFromConnection(status) {
              const selectedDevice = status?.selectedDevice;
              if (!selectedDevice?.serial) return;

              const connectionDevices = Array.isArray(status.devices) && status.devices.length
                ? status.devices
                : state.devices;
              if (connectionDevices && connectionDevices.length) {
                state.devices = connectionDevices;
              }
              if (!deviceBySerial(state.devices, selectedDevice.serial)) {
                state.devices = (state.devices || []).concat([selectedDevice]);
              }

              state.selectedDeviceSerial = selectedDevice.serial;
              devicePicker.disabled = false;
              devicePicker.innerHTML = '';
              state.devices.forEach(device => {
                const option = document.createElement('option');
                option.value = device.serial;
                option.textContent = deviceOptionLabel(device);
                option.disabled = device.state !== 'device';
                option.selected = device.serial === selectedDevice.serial;
                devicePicker.appendChild(option);
              });

              const selected = deviceBySerial(state.devices, selectedDevice.serial) || selectedDevice;
              devicePicker.value = selectedDevice.serial;
              setDeviceUiState(
                selected.state === 'device' ? DeviceUiState.CONNECTED : DeviceUiState.UNAVAILABLE,
                selected
              );
            }

            function computeCurrentBlockedReason(statusAvailability) {
              const annotate = toolMode.isAnnotateMode();
              const availability = statusAvailability ?? connectionUseCases.getState().availability;
              const resolverInput = availability
                ? { ...availability, unresponsive: unresponsiveTracker.isUnresponsive() }
                : { unresponsive: unresponsiveTracker.isUnresponsive() };
              const rawReason = computeBlockedReason(resolverInput, annotate);
              return blockedReasonDebouncer.observe(rawReason);
            }

            function recomputeInteractionBlockedReason() {
              const reason = computeCurrentBlockedReason();
              connectionUseCases.interactionBlocked(reason);
            }

            function applyConnectionStatus(status, options) {
              const connectionOptions = options || {};
              const previousConnectionState = connectionUseCases.getState();
              const hadEverConnected = previousConnectionState.hasEverConnected;
              const previousViewState = userConnectionState(previousConnectionState.current);

              // Compute the new blocked reason from the incoming availability
              // BEFORE dispatching, so STATUS_RECEIVED can write it atomically
              // (avoiding a stale-availability window between dispatches).
              const newBlockedReason = computeCurrentBlockedReason(status?.availability ?? null);

              // Capture the prior previousBlockedReason for transition detection.
              // STATUS_RECEIVED will roll it forward on dispatch.
              const priorPreviousBlockedReason = connectionUseCases.getState().previousBlockedReason;

              connectionUseCases.setStatus(status, newBlockedReason);
              const currentConnectionState = connectionUseCases.getState();

              // success → clear failure streak
              unresponsiveTracker.observeSuccess();

              // Mark frozen preview stale when the device's foreground activity has changed.
              const restoredActivity = state.preview?.activity ?? null;
              const currentActivity = status?.availability?.activity ?? null;
              if (state.preview?.obstructedBySystemUi) {
                state.preview.stale = true;
              } else if (state.preview && restoredActivity && currentActivity) {
                state.preview.stale = restoredActivity !== currentActivity;
              } else if (state.preview) {
                state.preview.stale = false;
              }
              // SIF-5: also evaluate time-based + disconnect-based staleness on every
              // status tick. OR'd with the activity-drift result above so existing
              // semantics are preserved.
              if (state.preview) {
                const bridgeConnection = userConnectionState(status) === 'ready' ? 'connected' : 'disconnected';
                const stalenessInput = {
                  preview: state.preview,
                  bridgeStatus: { connection: bridgeConnection },
                };
                state.preview.stale = state.preview.stale || evaluateStale(stalenessInput, Date.now());
              }

              // Detect blocked → unblocked transitions for select-mode auto-resume.
              // Use the captured prior previousBlockedReason vs the new reason.
              if (priorPreviousBlockedReason !== null && newBlockedReason === null) {
                if (toolMode.isSelectMode() && state.session) {
                  refreshPreview().catch(showError);
                }
              }
              // previousBlockedReason rolling is handled inside STATUS_RECEIVED.

              syncSelectedDeviceFromConnection(status);
              const viewState = userConnectionState(status);
              if (!shouldContinueLaunchConnectionRefresh(status)) clearLaunchConnectionRefresh();
              if (viewState === 'ready') {
                // hasEverConnected and lastReadyAt are set by STATUS_RECEIVED above.
                if (!connectionOptions.preservePreviewStale && !state.preview?.obstructedBySystemUi) markPreviewStale(false);
                startLivePreviewPolling();
              } else {
                stopLivePreviewPolling();
                if (currentConnectionState.hasEverConnected) markPreviewStale(true);
              }
              renderConnection(status);
              // Re-render the preview region so the canvas blocked-reason overlay and
              // stale-frame notice reflect the latest interactionBlockedReason / preview.stale.
              // Without this, the heartbeat-driven state update never reaches the canvas.
              renderPreviewRegion();
              const hasDirtyDraft = draftItemList().length > 0;
              if (viewState === 'ready') {
                if (hadEverConnected && previousViewState !== 'ready' && !currentConnectionState.interactionBlockedReason) {
                  applyReconnect({ targetStale: Boolean(state.preview?.stale) });
                }
              } else if (shouldShowDisconnectChoreography(viewState) && !state.preview && (hadEverConnected || hasDirtyDraft)) {
                // When a salvageable preview exists, the milder previewStaleBadge
                // ("Connection paused - showing last preview") owns the UX. The
                // modalCanvas overlay would suspend the badge surface class and
                // contradict that messaging, so we skip applyDisconnect here.
                applyDisconnect({ hasDirtyDraft });
              } else if (!currentConnectionState.interactionBlockedReason) {
                statusSurfaceRegistry.hide('canvasBlockedOverlay');
              }
              checkProtocolCompat(status);
              checkSidekickBuildEpoch(status);
              if (viewState === 'ready' && typeof hasPendingLatestStaleFrameRefresh === 'function' && hasPendingLatestStaleFrameRefresh()) {
                resumeLatestStaleFrameRefresh().catch(showError);
              } else if (viewState === 'ready' && annotateIntent && !draftFlow()) {
                const shouldResumeAnnotating = annotateIntentMatchesCurrentContext();
                clearAnnotateIntent();
                if (shouldResumeAnnotating) startDraftAnnotationFlow().catch(showError);
              }
            }

            function renderConnection(status) {
              const connectionState = connectionUseCases.getState();
              const viewState = userConnectionState(status);
              connectionCard.dataset.connectionState = viewState;
              connectionCard.dataset.reconnectVisible = viewState === 'reconnect' || connectionState.sessionsPollingPaused ? 'true' : 'false';
              connectionHeadline.textContent = viewState === 'reconnect'
                ? 'Reconnect'
                : (status?.headline || 'Connect to your app');
              connectionMessage.textContent = viewState === 'reconnect'
                ? 'The connection was interrupted. Your work is saved.'
                : (status?.message || "We'll find your phone and open the app for you.");
              const action = viewState === 'reconnect'
                ? 'RECONNECT'
                : (status?.primaryAction || (viewState === 'starting' ? 'OPEN_APP' : null));
              const resolvedAction = action || 'START';
              connectionPrimaryAction.textContent = connectionActionLabel(resolvedAction);
              connectionPrimaryAction.setAttribute('aria-label', connectionActionAccessibleLabel(resolvedAction));
              connectionPrimaryAction.disabled = connectionState.launchInFlight;
              connectionPrimaryAction.dataset.connectionAction = resolvedAction;
              if (connectionState.sessionsPollingPaused) {
                // Surface a sub-line indicating sessions polling is paused. The details panel
                // preserves line breaks and wraps long tokens through .connection-details pre.
                const baseDetails = connectionDetailsText(status);
                connectionDetailsBody.textContent = baseDetails
                  ? baseDetails + '\nReconnecting feedback updates…'
                  : 'Reconnecting feedback updates…';
              } else {
                connectionDetailsBody.textContent = connectionDetailsText(status);
              }
              connectionDetails.hidden = viewState === 'ready'
                && !connectionState.hasEverConnected
                && !connectionState.sessionsPollingPaused;
            }

            async function refreshConnection(options) {
              try {
                const status = await requestJson('/api/connection');
                applyConnectionStatus(status, options);
                return status;
              } catch (error) {
                unresponsiveTracker.observeFailure();
                recomputeInteractionBlockedReason();
                showError(error);
              }
            }

            function welcomeConnectionStatus() {
              return {
                state: 'WELCOME',
                headline: 'Connect to your app',
                message: "We'll find your phone and open the app for you.",
                primaryAction: 'START',
                packageName: state.session?.packageName || '',
                details: { deviceState: 'none', bridgeState: 'not checked' }
              };
            }

            async function launchApp() {
              clearLaunchConnectionRefresh();
              connectionUseCases.launchRequested();
              renderConnection(connectionUseCases.getState().current);
              let succeeded = false;
              try {
                const status = await requestJson('/api/app/launch', { method: 'POST' });
                applyConnectionStatus(status);
                scheduleLaunchConnectionRefresh();
                succeeded = true;
              } finally {
                if (succeeded) connectionUseCases.launchSucceeded();
                else connectionUseCases.launchFailed();
                renderConnection(connectionUseCases.getState().current);
              }
            }

            async function captureScreen() {
              if (!state.session) {
                showStatus('Connect to a session before capturing a screen.', { variant: 'warn', durationMs: 3000 });
                return;
              }
              await refreshPreview();
            }

            async function handleConnectionPrimaryAction() {
              const action = connectionPrimaryAction.dataset.connectionAction || 'START';
              if (action === 'START' || action === 'OPEN_APP' || action === 'RECONNECT') {
                await launchApp();
                return;
              }
              if (action === 'TRY_AGAIN') {
                await refreshDevices();
                await refreshConnection();
                return;
              }
              if (action === 'CHOOSE_DEVICE') {
                devicePicker.focus();
                return;
              }
              if (action === 'CAPTURE') {
                await captureScreen();
              }
            }


            let lastHeartbeatError = null;

            function handleHeartbeatError(cause) {
              const message = cause && cause.message ? cause.message : String(cause);
              if (message === lastHeartbeatError) return;
              lastHeartbeatError = message;
              showError(cause);
            }

            async function sendBridgeHeartbeat() {
              if (!state.session || !state.selectedDeviceSerial) return;
              await refreshConnection();
              lastHeartbeatError = null;
            }

            function scheduleNextHeartbeat() {
              if (!heartbeatPolling) return;
              const nextDelayMs = unresponsiveTracker.nextBackoffMs();
              heartbeatTimer = setTimeout(() => {
                heartbeatTimer = null;
                if (!heartbeatPolling) return;
                if (!state.selectedDeviceSerial) {
                  scheduleNextHeartbeat();
                  return;
                }
                sendBridgeHeartbeat()
                  .catch(handleHeartbeatError)
                  .finally(scheduleNextHeartbeat);
              }, nextDelayMs);
            }

            function startHeartbeatPolling() {
              stopHeartbeatPolling();
              heartbeatPolling = true;
              sendBridgeHeartbeat()
                .catch(handleHeartbeatError)
                .finally(scheduleNextHeartbeat);
            }

            function stopHeartbeatPolling() {
              heartbeatPolling = false;
              if (heartbeatTimer) clearTimeout(heartbeatTimer);
              heartbeatTimer = null;
            }
//#endregion connection.js

//#region studioWorkflow.js
// @requires (none)
const StudioWorkflowDecisionType = Object.freeze({
  ALLOW: 'allow',
  BLOCK: 'block',
  CONFIRM: 'confirm',
  IGNORE: 'ignore',
});

const StudioWorkflowAction = Object.freeze({
  ANNOTATE_CLICKED: 'annotate-clicked',
  SAVE_DRAFT_CLICKED: 'save-draft-clicked',
  COPY_PROMPT_CLICKED: 'copy-prompt-clicked',
  SAVE_TO_MCP_CLICKED: 'save-to-mcp-clicked',
  SESSION_SWITCH_REQUESTED: 'session-switch-requested',
  ASYNC_RESPONSE_RECEIVED: 'async-response-received',
  CLAIM_ITEM_CLICKED: 'claim-item-clicked',
  RESOLVE_ITEM_CLICKED: 'resolve-item-clicked',
  CONNECTION_STATUS_RECEIVED: 'connection-status-received',
});

const durableMutationActions = new Set([
  StudioWorkflowAction.SAVE_DRAFT_CLICKED,
  StudioWorkflowAction.COPY_PROMPT_CLICKED,
  StudioWorkflowAction.SAVE_TO_MCP_CLICKED,
  StudioWorkflowAction.CLAIM_ITEM_CLICKED,
  StudioWorkflowAction.RESOLVE_ITEM_CLICKED,
]);

const inFlightOperations = new Set([
  'capturing',
  'saving-draft',
  'copying-prompt',
  'saving-handoff',
  'claiming',
  'resolving',
]);

function allowStudioWorkflow(effect) {
  return Object.freeze({ type: StudioWorkflowDecisionType.ALLOW, effect });
}

function blockStudioWorkflow(reason, displaySurface) {
  return Object.freeze({ type: StudioWorkflowDecisionType.BLOCK, reason, displaySurface });
}

function confirmStudioWorkflow(boundaryKind, choices, reason) {
  return Object.freeze({
    type: StudioWorkflowDecisionType.CONFIRM,
    boundaryKind,
    choices: Object.freeze([...choices]),
    reason,
  });
}

function ignoreStudioWorkflow(reason) {
  return Object.freeze({ type: StudioWorkflowDecisionType.IGNORE, reason });
}

function workflowRisks(snapshot) {
  return new Set(snapshot?.risks || []);
}

function hasWorkflowRisk(snapshot, risk) {
  return workflowRisks(snapshot).has(risk);
}

function connectionReady(snapshot) {
  return (snapshot?.connection || 'initializing') === 'ready';
}

function annotateConnectionBlockReason(state) {
  if (state === 'no-device') return 'connection-no-device';
  if (state === 'unsupported') return 'connection-unsupported';
  if (state === 'blocked') return 'connection-blocked';
  return 'connection-not-ready';
}

function sessionClosed(snapshot) {
  return (snapshot?.activeSessionStatus || 'active') === 'closed';
}

function durableMutationInFlight(snapshot) {
  return inFlightOperations.has(snapshot?.operation || 'idle');
}

function decideAsyncResponse(snapshot) {
  if (
    snapshot?.currentGeneration != null &&
    snapshot?.eventGeneration != null &&
    snapshot.eventGeneration !== snapshot.currentGeneration
  ) {
    return ignoreStudioWorkflow('stale-generation');
  }
  if (
    snapshot?.activeSessionId &&
    snapshot?.eventSessionId &&
    snapshot.eventSessionId !== snapshot.activeSessionId
  ) {
    return ignoreStudioWorkflow('session-mismatch');
  }
  return allowStudioWorkflow('apply-response');
}

function decideStudioWorkflow(action, snapshot = {}) {
  if (action === StudioWorkflowAction.ASYNC_RESPONSE_RECEIVED) {
    return decideAsyncResponse(snapshot);
  }

  if (durableMutationInFlight(snapshot) && !(action === StudioWorkflowAction.ANNOTATE_CLICKED && snapshot?.operation === 'capturing')) {
    return blockStudioWorkflow('operation-in-flight', 'prompt-readiness');
  }

  if (sessionClosed(snapshot) && durableMutationActions.has(action)) {
    return blockStudioWorkflow('closed-session', 'history-panel');
  }

  if (action === StudioWorkflowAction.ANNOTATE_CLICKED) {
    if (!connectionReady(snapshot)) {
      const state = snapshot.connection || 'initializing';
      return blockStudioWorkflow(annotateConnectionBlockReason(state), 'connection-card');
    }
    const workspace = snapshot.workspace || 'empty';
    const canCapture = (workspace === 'empty' || workspace === 'saved-focus') && Boolean(snapshot.activeSessionId);
    if (workspace !== 'live-preview' && !canCapture) {
      return blockStudioWorkflow('no-live-preview', 'preview-frame');
    }
    return allowStudioWorkflow('capture-preview');
  }

  if (action === StudioWorkflowAction.SESSION_SWITCH_REQUESTED) {
    if (hasWorkflowRisk(snapshot, 'dirty-draft')) {
      return confirmStudioWorkflow('sessionSwitch', ['saveAndProceed', 'discardAndProceed', 'cancel'], 'dirty-draft');
    }
    return allowStudioWorkflow('open-session');
  }

  if (
    action === StudioWorkflowAction.SAVE_DRAFT_CLICKED ||
    action === StudioWorkflowAction.COPY_PROMPT_CLICKED ||
    action === StudioWorkflowAction.SAVE_TO_MCP_CLICKED
  ) {
    if (hasWorkflowRisk(snapshot, 'stale-preview') || hasWorkflowRisk(snapshot, 'activity-drift')) {
      return confirmStudioWorkflow('fingerprintMismatch', ['recapture', 'force', 'cancel'], 'stale-preview');
    }
    if (!connectionReady(snapshot) && (snapshot.workspace || 'empty') === 'frozen-draft') {
      return confirmStudioWorkflow('fingerprintMismatch', ['recapture', 'force', 'cancel'], 'connection-paused');
    }
    return allowStudioWorkflow(action === StudioWorkflowAction.COPY_PROMPT_CLICKED ? 'copy-prompt' : 'persist-feedback');
  }

  if (action === StudioWorkflowAction.CLAIM_ITEM_CLICKED || action === StudioWorkflowAction.RESOLVE_ITEM_CLICKED) {
    if (snapshot.targetItemExists === false) {
      return blockStudioWorkflow('missing-item', 'handoff-queue');
    }
    return allowStudioWorkflow(action === StudioWorkflowAction.CLAIM_ITEM_CLICKED ? 'claim-item' : 'resolve-item');
  }

  return allowStudioWorkflow('continue');
}
//#endregion studioWorkflow.js

//#region studioWorkflowAdapter.js
// @requires studioWorkflow.js, state.js, draftWorkspace.js
function currentStudioWorkflowConnection() {
  const raw = String(state.connection?.current?.state || '').toLowerCase();
  if (raw === 'ready') return 'ready';
  if (raw === 'no_device') return 'no-device';
  if (raw === 'unsupported_build') return 'unsupported';
  if (raw === 'open_app' || raw === 'reconnect' || raw === 'starting') return 'reconnecting';
  if (!state.selectedDeviceSerial && Array.isArray(state.devices) && state.devices.length === 0) return 'no-device';
  if (raw === 'check_phone' || raw === 'choose_device') return 'blocked';
  return 'initializing';
}

function currentStudioWorkflowWorkspace() {
  if (draftFlow()) return 'frozen-draft';
  if (state.preview) return 'live-preview';
  if (toolMode?.getState?.().focusedSavedItemId) return 'saved-focus';
  return 'empty';
}

function currentStudioWorkflowOperation() {
  if (pollingUseCases?.getState?.().promptActionInFlight) return 'saving-handoff';
  if (previewUseCases?.getState?.().inFlight) return 'capturing';
  if (toolMode?.getState?.().draftFlowStarting) return 'capturing';
  return 'idle';
}

function currentStudioWorkflowRisks() {
  const risks = [];
  if (draftFlow() && draftItemList().length) risks.push('dirty-draft');
  if (draftFlow() && draftWorkspace?.activityDriftWarning) risks.push('activity-drift');
  if (state.preview?.stale) risks.push('stale-preview');
  if (pollingUseCases?.getState?.().promptActionInFlight) risks.push('in-flight-mutation');
  return risks;
}

function currentStudioWorkflowSnapshot(patch = {}) {
  // `currentGeneration` reflects the polling FSM mutation counter so that
  // ASYNC_RESPONSE_RECEIVED can detect stale responses. The variable
  // `sessionMutationGeneration` is only referenced in a comment in `state.js`;
  // the live counter lives at `pollingUseCases.getState().mutationGeneration`.
  const generation = pollingUseCases?.getState?.()?.mutationGeneration;
  return {
    connection: currentStudioWorkflowConnection(),
    workspace: currentStudioWorkflowWorkspace(),
    operation: currentStudioWorkflowOperation(),
    risks: currentStudioWorkflowRisks(),
    activeSessionId: state.session?.sessionId || null,
    activeSessionStatus: state.session?.status || 'active',
    currentGeneration: typeof generation === 'number' ? generation : null,
    ...patch,
  };
}

function decideCurrentStudioWorkflow(action, patch = {}) {
  return decideStudioWorkflow(action, currentStudioWorkflowSnapshot(patch));
}

function studioWorkflowMessage(decision) {
  if (decision.reason === 'operation-in-flight') return 'Finish action first.';
  if (decision.reason === 'connection-no-device') return 'Connect a device first.';
  if (decision.reason === 'connection-unsupported') return 'Install a supported debug build.';
  if (decision.reason === 'connection-blocked') return 'Check your phone or choose a device.';
  if (decision.reason === 'connection-not-ready') return 'Open the app first.';
  if (decision.reason === 'closed-session') return 'Open a session first.';
  if (decision.reason === 'missing-item') return 'Item unavailable.';
  return 'Action blocked';
}

function focusStudioWorkflowSurface(decision) {
  if (decision.displaySurface !== 'connection-card') return;
  const raw = String(state.connection?.current?.state || '').toLowerCase();
  if (raw === 'choose_device') {
    devicePicker?.focus({ preventScroll: true });
    return;
  }
  if (decision.reason === 'connection-no-device') {
    document.getElementById('refreshDevicesButton')?.focus({ preventScroll: true });
    return;
  }
  connectionPrimaryAction?.focus({ preventScroll: true });
}

function surfaceStudioWorkflowDecision(decision) {
  if (!decision || decision.type === StudioWorkflowDecisionType.ALLOW || decision.type === StudioWorkflowDecisionType.IGNORE) return false;
  if (decision.type === StudioWorkflowDecisionType.CONFIRM) return false;
  const message = studioWorkflowMessage(decision);
  focusStudioWorkflowSurface(decision);
  if (typeof showStatus === 'function') {
    showStatus(message, { variant: 'warn', durationMs: 3500 });
  } else if (typeof showWarning === 'function') {
    showWarning(message);
  }
  return true;
}
//#endregion studioWorkflowAdapter.js

//#region draftWorkspaceHistory.js
// @requires (none)
// draftWorkspaceHistory.js - pure undo/redo helpers for DraftWorkspace items.

const DraftHistoryMaxDepth = 50;

function createEmptyDraftHistory() {
  return { undoStack: [], redoStack: [] };
}

function cloneDraftHistoryValue(value) {
  if (value == null) return value;
  return JSON.parse(JSON.stringify(value));
}

function pushDraftHistoryOp(stack, op) {
  const next = stack.concat(cloneDraftHistoryValue(op));
  while (next.length > DraftHistoryMaxDepth) next.shift();
  return next;
}

function recordDraftAdd(history, item) {
  return {
    undoStack: pushDraftHistoryOp(history?.undoStack || [], { kind: 'add', after: item }),
    redoStack: [],
  };
}

function recordDraftDelete(history, item, index) {
  return {
    undoStack: pushDraftHistoryOp(history?.undoStack || [], { kind: 'delete', before: item, index }),
    redoStack: [],
  };
}

function recordDraftUpdate(history, before, after) {
  return {
    undoStack: pushDraftHistoryOp(history?.undoStack || [], { kind: 'update', before, after }),
    redoStack: [],
  };
}

function sameDraftHistoryItem(left, right) {
  return Boolean(left?.draftItemId && right?.draftItemId && left.draftItemId === right.draftItemId);
}

function applyDraftInverse(op, items) {
  const next = items.map(cloneDraftHistoryValue);
  if (op.kind === 'add') {
    return next.filter((item) => !sameDraftHistoryItem(item, op.after));
  }
  if (op.kind === 'delete') {
    const restored = cloneDraftHistoryValue(op.before);
    const index = Number.isInteger(op.index) ? Math.max(0, Math.min(op.index, next.length)) : next.length;
    next.splice(index, 0, restored);
    return next;
  }
  if (op.kind === 'update') {
    return next.map((item) => sameDraftHistoryItem(item, op.before) ? cloneDraftHistoryValue(op.before) : item);
  }
  return next;
}

function applyDraftForward(op, items) {
  const next = items.map(cloneDraftHistoryValue);
  if (op.kind === 'add') return next.concat(cloneDraftHistoryValue(op.after));
  if (op.kind === 'delete') return next.filter((item) => !sameDraftHistoryItem(item, op.before));
  if (op.kind === 'update') {
    return next.map((item) => sameDraftHistoryItem(item, op.after) ? cloneDraftHistoryValue(op.after) : item);
  }
  return next;
}

function undoDraftHistory(history, items) {
  const undoStack = (history?.undoStack || []).slice();
  const op = undoStack.pop();
  if (!op) return { applied: false, reason: 'empty', history: history || createEmptyDraftHistory(), items };
  return {
    applied: true,
    history: {
      undoStack,
      redoStack: pushDraftHistoryOp(history?.redoStack || [], op),
    },
    items: applyDraftInverse(op, items || []),
  };
}

function redoDraftHistory(history, items) {
  const redoStack = (history?.redoStack || []).slice();
  const op = redoStack.pop();
  if (!op) return { applied: false, reason: 'empty', history: history || createEmptyDraftHistory(), items };
  return {
    applied: true,
    history: {
      undoStack: pushDraftHistoryOp(history?.undoStack || [], op),
      redoStack,
    },
    items: applyDraftForward(op, items || []),
  };
}
//#endregion draftWorkspaceHistory.js

//#region boundaryTriggers.js
// @requires (none)
// boundaryTriggers.js - frozen enum of context-transition triggers.

const Trigger = Object.freeze({
  SESSION_SWITCH: 'sessionSwitch',
  SESSION_CREATE: 'sessionCreate',
  SESSION_DELETE: 'sessionDelete',
  SCREEN_SWITCH: 'screenSwitch',
  NEW_CAPTURE: 'newCapture',
  ELEMENT_CLICK: 'elementClick',
  ESCAPE_KEY: 'escapeKey',
  BROWSER_REFRESH: 'browserRefresh',
  TAB_CLOSE: 'tabClose',
  ROUTE_CHANGE: 'routeChange',
  SERVER_DISCONNECT: 'serverDisconnect',
  RECONNECT: 'reconnect',
  BRIDGE_MISMATCH: 'bridgeMismatch',
  ACTIVITY_DRIFT: 'activityDrift',
  INACTIVITY: 'inactivity',
  EDITOR_BACK: 'editorBack',
});
//#endregion boundaryTriggers.js

//#region boundaryPolicy.js
// @requires boundaryTriggers.js
// boundaryPolicy.js - pure resolver for the context transition matrix.

function boundaryPolicy(trigger, state, _payload) {
  if (state === 'none' || state === 'saved') return 'pass';

  switch (trigger) {
    case Trigger.SESSION_SWITCH:
    case Trigger.SESSION_CREATE:
    case Trigger.SESSION_DELETE:
    case Trigger.ROUTE_CHANGE:
    case Trigger.EDITOR_BACK:
      return state === 'draft' ? 'boundaryDialog' : 'discardWithToast';

    case Trigger.SCREEN_SWITCH:
    case Trigger.NEW_CAPTURE:
      return state === 'draft' ? 'preserve' : 'discardWithToast';

    case Trigger.ELEMENT_CLICK:
      return state === 'draft' ? 'preserve' : 'silentSwap';

    case Trigger.ESCAPE_KEY:
      return state === 'draft' ? 'discardConfirm' : 'discardWithToast';

    case Trigger.BROWSER_REFRESH:
    case Trigger.TAB_CLOSE:
      return state === 'draft' ? 'beforeunloadGuard' : 'silentLoss';

    case Trigger.SERVER_DISCONNECT:
      return 'retainWithBadge';

    case Trigger.RECONNECT:
      return 'staleRevalidate';

    case Trigger.BRIDGE_MISMATCH:
      return state === 'draft' ? 'retainAndMigrate' : 'discardWithToast';

    case Trigger.ACTIVITY_DRIFT:
    case Trigger.INACTIVITY:
      return 'retain';

    default:
      return 'pass';
  }
}
//#endregion boundaryPolicy.js

