//#region application/consoleEffects.js
// @requires (none)
async function runConsoleEffect(effect, environment) {
  const dispatch = environment.dispatch;
  const ports = environment.ports || {};
  try {
    switch (effect.kind) {
      case 'openSession': {
        const session = await ports.sessionApi.openSession(effect.sessionId);
        dispatch({
          type: 'SESSION_OPEN_SUCCEEDED',
          requestId: effect.requestId,
          sessionId: effect.sessionId,
          generation: effect.generation,
          session,
        });
        return;
      }
      case 'capturePreview': {
        const preview = await ports.previewApi.capturePreview(effect.sessionId);
        dispatch({
          type: 'PREVIEW_CAPTURE_SUCCEEDED',
          requestId: effect.requestId,
          sessionId: effect.sessionId,
          generation: effect.generation,
          preview,
        });
        return;
      }
      case 'saveDraft': {
        const result = await ports.sessionApi.saveDraft(effect.sessionId, effect.items || []);
        dispatch({
          type: 'DRAFT_SAVE_SUCCEEDED',
          requestId: effect.requestId,
          sessionId: effect.sessionId,
          targetSessionId: effect.targetSessionId,
          workspaceId: effect.workspaceId,
          generation: effect.generation,
          session: result?.session || result,
        });
        return;
      }
      case 'persistRecovery':
        await ports.draftStorage.saveRecovery(effect.sessionId, effect.workspace);
        dispatch({ type: 'RECOVERY_PERSISTED', sessionId: effect.sessionId });
        return;
      case 'copyPrompt':
        await ports.clipboard.writeText(effect.markdown || '');
        dispatch({
          type: 'PROMPT_COPY_SUCCEEDED',
          requestId: effect.requestId,
          sessionId: effect.sessionId,
          workspaceId: effect.workspaceId,
          generation: effect.generation,
        });
        return;
      case 'deleteRecovery':
        await ports.draftStorage.deleteRecovery(effect.sessionId, effect.workspaceId);
        dispatch({ type: 'RECOVERY_DELETED', sessionId: effect.sessionId, workspaceId: effect.workspaceId });
        return;
      case 'showStatus':
        dispatch({ type: 'STATUS_SHOWN', message: effect.message, variant: effect.variant, assertive: effect.assertive === true });
        return;
      default:
        dispatch({ type: 'CONSOLE_EFFECT_FAILED', effect, error: 'Unknown effect kind: ' + effect.kind });
    }
  } catch (cause) {
    dispatch({ type: 'CONSOLE_EFFECT_FAILED', effect, error: cause && cause.message ? cause.message : String(cause) });
  }
}
//#endregion application/consoleEffects.js

//#region domain/consoleWorkflowProjection.js
// @requires studioWorkflow.js, domain/workspaceState.js
function workflowConnectionFromState(state) {
  const raw = String(state.connection?.current?.state || '').toLowerCase();
  if (raw === 'ready') return 'ready';
  if (raw === 'no_device') return 'no-device';
  if (raw === 'check_phone' || raw === 'choose_device') return 'blocked';
  if (raw === 'unsupported_build') return 'unsupported';
  if (raw === 'open_app' || raw === 'reconnect' || raw === 'starting') return 'reconnecting';
  return 'initializing';
}

function workflowWorkspaceFromState(state) {
  if (state.workspace?.kind === WorkspaceKind.LIVE_PREVIEW) return 'live-preview';
  if (state.workspace?.kind === WorkspaceKind.DRAFT) return 'frozen-draft';
  if (state.workspace?.kind === WorkspaceKind.SAVED_FOCUS) return 'saved-focus';
  if (state.workspace?.kind === WorkspaceKind.RECOVERY) return 'recovery';
  return 'empty';
}

function workflowRisksFromState(state) {
  const risks = [];
  if (state.workspace?.kind === WorkspaceKind.DRAFT && state.workspace.items?.length) risks.push('dirty-draft');
  if (state.workspace?.kind === WorkspaceKind.DRAFT && state.workspace.activityDriftWarning) risks.push('activity-drift');
  if (state.workspace?.kind === WorkspaceKind.LIVE_PREVIEW && state.workspace.preview?.stale) risks.push('stale-preview');
  if (state.promptAction?.inFlight) risks.push('in-flight-mutation');
  return risks;
}

function workflowSnapshotFromState(state, patch = {}) {
  return Object.freeze({
    connection: workflowConnectionFromState(state),
    workspace: workflowWorkspaceFromState(state),
    operation: state.promptAction?.inFlight ? 'saving-handoff' : 'idle',
    risks: workflowRisksFromState(state),
    activeSessionId: state.activeSessionId || null,
    activeSessionStatus: state.sessionsById?.[state.activeSessionId]?.status || 'active',
    currentGeneration: state.effectsGeneration,
    ...patch,
  });
}

function workflowStatus(decision) {
  if (decision.reason === 'operation-in-flight') {
    return Object.freeze({ message: 'Finish the current handoff action before switching sessions.', variant: 'warn', assertive: false });
  }
  if (decision.reason === 'connection-no-device') {
    return Object.freeze({ message: 'Connect a device before annotating.', variant: 'warn', assertive: false });
  }
  if (decision.reason === 'connection-unsupported') {
    return Object.freeze({ message: 'Install a supported debug build before annotating.', variant: 'warn', assertive: false });
  }
  if (decision.reason === 'connection-blocked') {
    return Object.freeze({ message: 'Check the device or choose another device before annotating.', variant: 'warn', assertive: false });
  }
  if (decision.reason === 'connection-not-ready') {
    return Object.freeze({ message: 'Open the app before annotating.', variant: 'warn', assertive: false });
  }
  if (decision.reason === 'closed-session') {
    return Object.freeze({ message: 'Reopen the session or create a new active session before changing feedback.', variant: 'warn', assertive: false });
  }
  return Object.freeze({ message: 'This action is blocked by the current Studio workflow state.', variant: 'warn', assertive: false });
}
//#endregion domain/consoleWorkflowProjection.js

//#region domain/consoleAppState.js
// @requires domain/workspaceState.js
function normalizeSessions(sessions = []) {
  const sessionsById = {};
  const sessionOrder = [];
  for (const session of sessions || []) {
    if (!session?.sessionId) continue;
    sessionsById[session.sessionId] = cloneConsoleValue(session);
    if (!sessionOrder.includes(session.sessionId)) sessionOrder.push(session.sessionId);
  }
  return { sessionsById, sessionOrder };
}

function createInitialConsoleAppState(options = {}) {
  const normalized = normalizeSessions(options.sessions || []);
  return Object.freeze({
    activeSessionId: options.activeSessionId || null,
    sessionsById: Object.freeze(normalized.sessionsById),
    sessionOrder: Object.freeze(normalized.sessionOrder),
    workspace: options.workspace || emptyWorkspace(),
    tool: Object.freeze(options.tool || { mode: 'select' }),
    connection: Object.freeze(options.connection || { current: null }),
    polling: Object.freeze(options.polling || { pendingMutationCount: 0 }),
    pendingBoundary: options.pendingBoundary || null,
    promptAction: Object.freeze(options.promptAction || { inFlight: false }),
    effectsGeneration: Number(options.effectsGeneration || 1),
    status: options.status || null,
  });
}

function replaceConsoleState(state, patch) {
  return Object.freeze({ ...state, ...patch });
}

function replaceSessions(state, sessions) {
  const normalized = normalizeSessions(sessions);
  return replaceConsoleState(state, {
    sessionsById: Object.freeze(normalized.sessionsById),
    sessionOrder: Object.freeze(normalized.sessionOrder),
  });
}

function upsertSession(state, session) {
  if (!session?.sessionId) return state;
  const sessionsById = Object.freeze({
    ...state.sessionsById,
    [session.sessionId]: cloneConsoleValue(session),
  });
  const sessionOrder = state.sessionOrder.includes(session.sessionId)
    ? state.sessionOrder
    : Object.freeze([...state.sessionOrder, session.sessionId]);
  return replaceConsoleState(state, { sessionsById, sessionOrder });
}

function nextGeneration(state) {
  return state.effectsGeneration + 1;
}

function nextRequestId(prefix, generation) {
  return `${prefix}-${generation}`;
}
//#endregion domain/consoleAppState.js

//#region domain/consoleInvariants.js
// @requires domain/workspaceState.js
function assertConsoleInvariants(state) {
  if (!state) throw new Error('Console state is required');
  const workspace = state.workspace;
  if (!workspace?.kind) throw new Error('Console state requires workspace.kind');
  if (workspace.kind === WorkspaceKind.DRAFT) {
    if (!workspace.context?.sessionId) throw new Error('Draft workspace requires context.sessionId');
    if (state.activeSessionId !== workspace.context.sessionId) {
      throw new Error('Draft workspace session must match activeSessionId');
    }
    if (!workspace.context.previewId) throw new Error('Draft workspace requires context.previewId');
    if (!workspace.context.screenId) throw new Error('Draft workspace requires context.screenId');
    if (workspace.focusedItemId && workspace.kind === WorkspaceKind.SAVED_FOCUS) {
      throw new Error('Draft focus and saved focus cannot coexist');
    }
  }
  if (workspace.kind === WorkspaceKind.SAVED_FOCUS && workspace.itemId && workspace.focusedItemId) {
    throw new Error('Saved focus cannot carry draft focus');
  }
  if (state.pendingBoundary && workspace.kind !== WorkspaceKind.DRAFT) {
    throw new Error('pendingBoundary requires an active draft workspace');
  }
  return true;
}
//#endregion domain/consoleInvariants.js

//#region domain/consoleReducer.js
// @requires studioWorkflow.js, domain/consoleWorkflowProjection.js, domain/workspaceState.js, domain/consoleAppState.js, domain/consoleInvariants.js
function reduceConsoleAppState(state = createInitialConsoleAppState(), event = {}) {
  let result;
  switch (event.type) {
    case 'SESSION_ROW_CLICKED':
      result = reduceSessionRowClicked(state, event);
      break;
    case 'SESSION_OPEN_SUCCEEDED':
      result = reduceSessionOpenSucceeded(state, event);
      break;
    case 'SESSIONS_POLL_SUCCEEDED':
      result = reduceSessionsPollSucceeded(state, event);
      break;
    case 'ANNOTATE_CLICKED':
      result = reduceAnnotateClicked(state);
      break;
    case 'DRAFT_STARTED_FROM_PREVIEW':
      result = reduceDraftStartedFromPreview(state, event);
      break;
    case 'DRAFT_TARGET_SELECTED':
      result = reduceDraftTargetSelected(state, event);
      break;
    case 'DRAFT_COMMENT_CHANGED':
      result = reduceDraftCommentChanged(state, event);
      break;
    case 'DRAFT_ITEM_FOCUSED':
      result = reduceDraftItemFocused(state, event);
      break;
    case 'DRAFT_ITEM_DELETED':
      result = reduceDraftItemDeleted(state, event);
      break;
    case 'DRAFT_SELECTION_CLEARED':
      result = isDraftWorkspace(state.workspace)
        ? { state: replaceConsoleState(state, { workspace: draftWorkspaceWithPatch(state.workspace, { currentSelection: null }) }), effects: [] }
        : { state, effects: [] };
      break;
    case 'DRAFT_DISCARDED':
      result = reduceDraftDiscarded(state);
      break;
    case 'PREVIEW_CAPTURE_SUCCEEDED':
      result = reducePreviewCaptureSucceeded(state, event);
      break;
    case 'BOUNDARY_CANCEL_CLICKED':
      result = { state: replaceConsoleState(state, { pendingBoundary: null }), effects: [] };
      break;
    case 'BOUNDARY_KEEP_RECOVERY_CLICKED':
      result = reduceBoundaryKeepRecoveryClicked(state);
      break;
    case 'BOUNDARY_DISCARD_CLICKED':
      result = reduceBoundaryDiscardClicked(state);
      break;
    case 'BOUNDARY_SAVE_DRAFT_CLICKED':
    case 'SAVE_TO_MCP_CLICKED':
      result = reduceSaveDraftClicked(state);
      break;
    case 'COPY_PROMPT_CLICKED':
      result = reduceCopyPromptClicked(state);
      break;
    case 'DRAFT_SAVE_SUCCEEDED':
      result = reduceDraftSaveSucceeded(state, event);
      break;
    case 'DRAFT_SAVE_FAILED':
      result = reduceDraftSaveFailed(state, event);
      break;
    case 'PROMPT_COPY_SUCCEEDED':
      result = reducePromptCopySucceeded(state, event);
      break;
    case 'PROMPT_COPY_FAILED':
      result = reducePromptCopyFailed(state, event);
      break;
    case 'UNDO_CLICKED':
    case 'REDO_CLICKED':
      result = { state, effects: [] };
      break;
    default:
      result = { state, effects: [] };
  }
  assertConsoleInvariants(result.state);
  return result;
}

function reduceSessionRowClicked(state, event) {
  const sessionId = event.sessionId || null;
  if (!sessionId || sessionId === state.activeSessionId) return { state, effects: [] };
  const decision = decideStudioWorkflow(
    StudioWorkflowAction.SESSION_SWITCH_REQUESTED,
    workflowSnapshotFromState(state, { eventSessionId: sessionId }),
  );
  if (decision.type === StudioWorkflowDecisionType.BLOCK) {
    return { state: replaceConsoleState(state, { status: workflowStatus(decision) }), effects: [] };
  }
  if (isDraftWorkspace(state.workspace) && state.workspace.context.sessionId !== sessionId) {
    return {
      state: replaceConsoleState(state, {
        pendingBoundary: Object.freeze({
          kind: 'session-switch',
          fromSessionId: state.workspace.context.sessionId,
          targetSessionId: sessionId,
          draftSummary: Object.freeze({
            itemCount: state.workspace.items.length,
            missingCommentCount: state.workspace.items.filter((item) => !String(item.comment || '').trim()).length,
            previewId: state.workspace.context.previewId,
          }),
        }),
      }),
      effects: [],
    };
  }
  const generation = nextGeneration(state);
  return {
    state: replaceConsoleState(state, { effectsGeneration: generation }),
    effects: [Object.freeze({ kind: 'openSession', requestId: nextRequestId('open-session', generation), sessionId, generation })],
  };
}

function reduceSessionOpenSucceeded(state, event) {
  if (event.generation !== state.effectsGeneration) return { state, effects: [] };
  let next = upsertSession(state, event.session);
  next = replaceConsoleState(next, {
    activeSessionId: event.sessionId,
    workspace: livePreviewWorkspace(event.sessionId, null),
    pendingBoundary: null,
    tool: Object.freeze({ mode: 'select' }),
  });
  return { state: next, effects: [] };
}

function reduceSessionsPollSucceeded(state, event) {
  if (event.generation && event.generation !== state.effectsGeneration) return { state, effects: [] };
  return { state: replaceSessions(state, event.sessions || []), effects: [] };
}

function reduceAnnotateClicked(state) {
  const decision = decideStudioWorkflow(
    StudioWorkflowAction.ANNOTATE_CLICKED,
    workflowSnapshotFromState(state),
  );
  if (decision.type === StudioWorkflowDecisionType.BLOCK) {
    return { state: replaceConsoleState(state, { status: workflowStatus(decision) }), effects: [] };
  }
  if (!state.activeSessionId || isDraftWorkspace(state.workspace)) return { state, effects: [] };
  const generation = nextGeneration(state);
  return {
    state: replaceConsoleState(state, {
      effectsGeneration: generation,
      tool: Object.freeze({ mode: 'annotate', hoveredTarget: null, drag: null }),
    }),
    effects: [Object.freeze({ kind: 'capturePreview', requestId: nextRequestId('capture-preview', generation), sessionId: state.activeSessionId, generation })],
  };
}

function reduceDraftStartedFromPreview(state, event) {
  return {
    state: replaceConsoleState(state, {
      activeSessionId: event.sessionId,
      workspace: draftWorkspaceFromPreview(event.sessionId, event.preview, event),
      tool: Object.freeze({ mode: 'annotate', hoveredTarget: null, drag: null }),
      pendingBoundary: null,
    }),
    effects: [],
  };
}

function reduceDraftTargetSelected(state, event) {
  if (!isDraftWorkspace(state.workspace)) return { state, effects: [] };
  const item = Object.freeze({
    itemId: event.itemId || event.annotationId || `draft-${state.workspace.items.length + 1}`,
    annotationId: event.annotationId || event.itemId || `draft-${state.workspace.items.length + 1}`,
    sequenceNumber: state.workspace.items.length + 1,
    comment: event.comment || '',
    selection: cloneConsoleValue(event.selection || null),
    targetEvidence: cloneConsoleValue(event.targetEvidence || null),
  });
  return {
    state: replaceConsoleState(state, {
      workspace: draftWorkspaceWithPatch(state.workspace, {
        items: [...state.workspace.items, item],
        focusedItemId: item.itemId,
        currentSelection: item.selection,
      }),
    }),
    effects: [],
  };
}

function reduceDraftCommentChanged(state, event) {
  if (!isDraftWorkspace(state.workspace)) return { state, effects: [] };
  const itemId = event.itemId || state.workspace.focusedItemId;
  const items = state.workspace.items.map((item) =>
    (item.itemId === itemId || item.annotationId === itemId) ? { ...item, comment: event.comment || '' } : item,
  );
  return {
    state: replaceConsoleState(state, {
      workspace: draftWorkspaceWithPatch(state.workspace, { items }),
    }),
    effects: [],
  };
}

function reduceDraftItemFocused(state, event) {
  if (!isDraftWorkspace(state.workspace)) return { state, effects: [] };
  const item = state.workspace.items.find((candidate) => candidate.itemId === event.itemId || candidate.annotationId === event.itemId);
  if (!item) return { state, effects: [] };
  return {
    state: replaceConsoleState(state, {
      workspace: draftWorkspaceWithPatch(state.workspace, {
        focusedItemId: item.itemId,
        currentSelection: item.selection || null,
      }),
    }),
    effects: [],
  };
}

function reduceDraftItemDeleted(state, event) {
  if (!isDraftWorkspace(state.workspace)) return { state, effects: [] };
  const removed = state.workspace.items.find((item) => item.itemId === event.itemId || item.annotationId === event.itemId);
  if (!removed) return { state, effects: [] };
  const items = state.workspace.items.filter((item) => item.itemId !== event.itemId && item.annotationId !== event.itemId);
  const focusedItemId = state.workspace.focusedItemId === removed.itemId ? null : state.workspace.focusedItemId;
  return {
    state: replaceConsoleState(state, {
      workspace: draftWorkspaceWithPatch(state.workspace, {
        items,
        focusedItemId,
        currentSelection: focusedItemId ? state.workspace.currentSelection : null,
      }),
    }),
    effects: [],
  };
}

function reduceDraftDiscarded(state) {
  if (!isDraftWorkspace(state.workspace)) return { state, effects: [] };
  return {
    state: replaceConsoleState(state, {
      workspace: livePreviewWorkspace(state.workspace.context.sessionId, null),
      pendingBoundary: null,
      promptAction: Object.freeze({ inFlight: false }),
      tool: Object.freeze({ mode: 'select' }),
    }),
    effects: [Object.freeze({
      kind: 'deleteRecovery',
      sessionId: state.workspace.context.sessionId,
      workspaceId: state.workspace.context.workspaceId,
    })],
  };
}

function reducePreviewCaptureSucceeded(state, event) {
  if (event.generation !== state.effectsGeneration) return { state, effects: [] };
  if (event.sessionId !== state.activeSessionId) return { state, effects: [] };
  if (isDraftWorkspace(state.workspace)) return { state, effects: [] };
  return {
    state: replaceConsoleState(state, {
      workspace: livePreviewWorkspace(event.sessionId, event.preview),
    }),
    effects: [],
  };
}

function reduceBoundaryKeepRecoveryClicked(state) {
  if (!state.pendingBoundary || !isDraftWorkspace(state.workspace)) return { state, effects: [] };
  const generation = nextGeneration(state);
  const recovery = cloneConsoleValue(state.workspace);
  const targetSessionId = state.pendingBoundary.targetSessionId;
  return {
    state: replaceConsoleState(state, {
      effectsGeneration: generation,
      activeSessionId: targetSessionId,
      workspace: livePreviewWorkspace(targetSessionId, null),
      pendingBoundary: null,
      tool: Object.freeze({ mode: 'select' }),
    }),
    effects: [
      Object.freeze({ kind: 'persistRecovery', sessionId: recovery.context.sessionId, workspace: recovery }),
      Object.freeze({ kind: 'openSession', requestId: nextRequestId('open-session', generation), sessionId: targetSessionId, generation }),
    ],
  };
}

function reduceBoundaryDiscardClicked(state) {
  if (!state.pendingBoundary) return { state, effects: [] };
  const generation = nextGeneration(state);
  const targetSessionId = state.pendingBoundary.targetSessionId;
  return {
    state: replaceConsoleState(state, {
      effectsGeneration: generation,
      activeSessionId: targetSessionId,
      workspace: livePreviewWorkspace(targetSessionId, null),
      pendingBoundary: null,
      tool: Object.freeze({ mode: 'select' }),
    }),
    effects: [Object.freeze({ kind: 'openSession', requestId: nextRequestId('open-session', generation), sessionId: targetSessionId, generation })],
  };
}

function reduceSaveDraftClicked(state) {
  if (!isDraftWorkspace(state.workspace)) return { state, effects: [] };
  const generation = nextGeneration(state);
  const targetSessionId = state.pendingBoundary?.targetSessionId || state.activeSessionId;
  return {
    state: replaceConsoleState(state, {
      effectsGeneration: generation,
      promptAction: Object.freeze({ inFlight: true }),
    }),
    effects: [Object.freeze({
      kind: 'saveDraft',
      requestId: nextRequestId('save-draft', generation),
      sessionId: state.workspace.context.sessionId,
      targetSessionId,
      workspaceId: state.workspace.context.workspaceId,
      items: cloneConsoleValue(state.workspace.items),
      generation,
    })],
  };
}

function reduceCopyPromptClicked(state) {
  if (!isDraftWorkspace(state.workspace)) return { state, effects: [] };
  const readyItems = state.workspace.items.filter((item) => String(item.comment || '').trim());
  if (!readyItems.length) return { state, effects: [] };
  const generation = nextGeneration(state);
  const markdown = readyItems
    .map((item, index) => `${index + 1}. ${item.comment || ''}`.trim())
    .join('\n');
  return {
    state: replaceConsoleState(state, {
      effectsGeneration: generation,
      promptAction: Object.freeze({ inFlight: true }),
    }),
    effects: [Object.freeze({
      kind: 'copyPrompt',
      requestId: nextRequestId('copy-prompt', generation),
      sessionId: state.workspace.context.sessionId,
      workspaceId: state.workspace.context.workspaceId,
      markdown,
      generation,
    })],
  };
}

function reduceDraftSaveSucceeded(state, event) {
  if (event.generation !== state.effectsGeneration) return { state, effects: [] };
  if (!isDraftWorkspace(state.workspace)) return { state, effects: [] };
  if (event.workspaceId && event.workspaceId !== state.workspace.context.workspaceId) return { state, effects: [] };
  const nextSessionId = state.pendingBoundary?.targetSessionId || event.targetSessionId || event.sessionId || state.activeSessionId;
  let next = event.session ? upsertSession(state, event.session) : state;
  next = replaceConsoleState(next, {
    activeSessionId: nextSessionId,
    workspace: livePreviewWorkspace(nextSessionId, null),
    pendingBoundary: null,
    promptAction: Object.freeze({ inFlight: false }),
    tool: Object.freeze({ mode: 'select' }),
  });
  return { state: next, effects: [] };
}

function reduceDraftSaveFailed(state, event) {
  if (event.generation !== state.effectsGeneration) return { state, effects: [] };
  if (!isDraftWorkspace(state.workspace)) return { state, effects: [] };
  if (event.workspaceId && event.workspaceId !== state.workspace.context.workspaceId) return { state, effects: [] };
  return {
    state: replaceConsoleState(state, {
      promptAction: Object.freeze({ inFlight: false }),
      status: Object.freeze({ message: event.error || 'Could not save draft.', variant: 'error', assertive: true }),
    }),
    effects: [],
  };
}

function reducePromptCopySucceeded(state, event) {
  if (event.generation !== state.effectsGeneration) return { state, effects: [] };
  return {
    state: replaceConsoleState(state, {
      promptAction: Object.freeze({ inFlight: false }),
      status: Object.freeze({ message: 'Prompt copied.', variant: 'success', assertive: false }),
    }),
    effects: [],
  };
}

function reducePromptCopyFailed(state, event) {
  if (event.generation !== state.effectsGeneration) return { state, effects: [] };
  return {
    state: replaceConsoleState(state, {
      promptAction: Object.freeze({ inFlight: false }),
      status: Object.freeze({ message: event.error || 'Could not copy prompt.', variant: 'error', assertive: true }),
    }),
    effects: [],
  };
}
//#endregion domain/consoleReducer.js

//#region application/consoleStore.js
// @requires domain/consoleReducer.js, domain/consoleInvariants.js
function createConsoleStore(options = {}) {
  let current = options.initialState || createInitialConsoleAppState();
  const render = typeof options.render === 'function' ? options.render : () => {};
  const onEffects = typeof options.onEffects === 'function' ? options.onEffects : () => {};
  assertConsoleInvariants(current);
  function getState() {
    return current;
  }
  function dispatch(event) {
    const result = reduceConsoleAppState(current, event);
    assertConsoleInvariants(result.state);
    current = result.state;
    render(current);
    onEffects(result.effects, current);
    return result.effects;
  }
  render(current);
  return Object.freeze({ getState, dispatch });
}
//#endregion application/consoleStore.js

//#region availability.js
// @requires state.js
// availability.js
function computeBlockedReason(status, isAnnotateMode) {
  if (!status) return null;
  if (status.screenInteractive === false) return 'screenOff';
  if (status.keyguardLocked === true) return 'locked';
  if (status.appForeground === false) return 'background';
  if (status.pictureInPicture === true) return 'pictureInPicture';
  if (status.unresponsive === true) return 'unresponsive';
  if (isAnnotateMode && (status.rootsCount === 0)) return 'noComposeUi';
  return null;
}

function createBlockedReasonDebouncer({ delayMs = 300, now = () => Date.now() } = {}) {
  let committed = null;
  let pending = null;
  let pendingSince = 0;
  return {
    observe(reason) {
      if (reason === null) {
        pending = null;
        pendingSince = 0;
        committed = null;
        return null;
      }
      if (reason === committed) return committed;
      if (pending !== reason) {
        pending = reason;
        pendingSince = now();
        return committed;
      }
      if (now() - pendingSince >= delayMs) {
        committed = reason;
        pending = null;
        pendingSince = 0;
        return committed;
      }
      return committed;
    }
  };
}

const UNRESPONSIVE_BACKOFF_MS = [1000, 2000, 5000, 10000, 30000];

function createUnresponsiveTracker({ threshold = 3 } = {}) {
  let streak = 0;
  return {
    observeFailure() {
      streak += 1;
      return streak >= threshold;
    },
    observeSuccess() {
      streak = 0;
    },
    isUnresponsive() {
      return streak >= threshold;
    },
    nextBackoffMs() {
      const idx = Math.min(streak, UNRESPONSIVE_BACKOFF_MS.length - 1);
      return UNRESPONSIVE_BACKOFF_MS[idx];
    },
  };
}
//#endregion availability.js

//#region beforeunloadGuard.js
