function shouldGuardUnload(pendingItemsCount, editorState = null) {
  if (editorState) {
    return boundaryPolicy(Trigger.BROWSER_REFRESH, editorState, {}) === 'beforeunloadGuard';
  }
  return Number(pendingItemsCount) > 0;
}
