//#region historyPendingDedupe.js
// @requires state.js
// historyPendingDedupe.js - removes local recovery items already persisted by the server.

function persistedItemsForHistoryDedupe(session) {
  if (state.session?.sessionId === session?.sessionId && Array.isArray(state.session?.items)) return state.session.items;
  return Array.isArray(session?.items) ? session.items : [];
}

function persistedClientDraftKey(item) {
  if (!item?.clientWorkspaceId || !item?.clientDraftItemId) return null;
  return item.clientWorkspaceId + '\u0000' + item.clientDraftItemId;
}

function pendingClientDraftKey(item, workspaceId) {
  if (!workspaceId || !item?.draftItemId) return null;
  return workspaceId + '\u0000' + item.draftItemId;
}

function dropEmptyHistoryPendingItems(items) {
  let dropped = 0;
  const kept = (items || []).filter((item) => {
    const comment = String(item?.comment || '');
    if (comment.length === 0) {
      dropped += 1;
      return false;
    }
    return true;
  });
  if (dropped > 0) {
    console.info(`[draft-recovery] skipped ${dropped} empty-comment entries`);
  }
  return kept;
}

function dedupePendingHistoryItemsForSession(session, pendingItems, workspaceId) {
  const filteredPendingItems = dropEmptyHistoryPendingItems(pendingItems);
  const persisted = persistedItemsForHistoryDedupe(session);
  const persistedClientKeys = new Set(persisted.map(persistedClientDraftKey).filter(Boolean));
  return filteredPendingItems.filter((item) => {
    const clientKey = pendingClientDraftKey(item, workspaceId);
    if (!clientKey) return false;
    return !persistedClientKeys.has(clientKey);
  });
}

function newestDedupedHistoryRecoveryItems(session, recoveryCandidates) {
  return [...(recoveryCandidates || [])]
    .map((workspace) => ({
      workspace,
      items: dedupePendingHistoryItemsForSession(
        session,
        Array.isArray(workspace?.items) ? workspace.items : [],
        workspace?.workspaceId || null
      ),
    }))
    .filter((candidate) => candidate.items.length)
    .sort((left, right) =>
      (left.workspace?.updatedAtEpochMillis || 0) - (right.workspace?.updatedAtEpochMillis || 0)
    )
    .at(-1)?.items || [];
}
//#endregion historyPendingDedupe.js

//#region domain/consoleEvents.js
// @requires (none)
function requireEventString(name, value) {
  const normalized = String(value || '').trim();
  if (!normalized) throw new Error(`${name} is required`);
  return normalized;
}

function freezeEvent(event) {
  return Object.freeze(event);
}

const ConsoleEvents = Object.freeze({
  sessionRowClicked(sessionId) {
    return freezeEvent({
      type: 'SESSION_ROW_CLICKED',
      sessionId: requireEventString('sessionId', sessionId),
    });
  },

  annotateClicked() {
    return freezeEvent({ type: 'ANNOTATE_CLICKED' });
  },

  draftTargetSelected(payload) {
    return freezeEvent({
      type: 'DRAFT_TARGET_SELECTED',
      ...payload,
    });
  },

  draftCommentChanged(itemId, comment) {
    return freezeEvent({
      type: 'DRAFT_COMMENT_CHANGED',
      itemId: itemId || null,
      comment: String(comment || ''),
    });
  },

  previewCaptureSucceeded(sessionId, preview, generation) {
    return freezeEvent({
      type: 'PREVIEW_CAPTURE_SUCCEEDED',
      sessionId: requireEventString('sessionId', sessionId),
      preview,
      generation,
    });
  },
});
//#endregion domain/consoleEvents.js

//#region historySessionRow.js
// @requires state.js, draftWorkspace.js, boundaryDialogVariants.js
// historySessionRow.js - session row HTML helpers for the history drawer.

function historySessionRowHtml({ session, label, pendingSummary, pips, activeId, busy, navigationBusy }) {
  return '<div class="history-item session-row ' + (session.sessionId === activeId ? 'is-active ' : '') + (busy ? 'is-busy' : '') + '" role="button" tabindex="0" aria-busy="' + (busy ? 'true' : 'false') + '" aria-disabled="' + (navigationBusy ? 'true' : 'false') + '" data-session-id="' + escapeHtml(session.sessionId) + '">' +
    '<span class="hi-head">' +
      '<span class="hi-title">' + escapeHtml(label) + '</span>' +
      historySessionDeleteButtonHtml(session, label, navigationBusy) +
    '</span>' +
    '<span class="hi-meta">' + escapeHtml(formatSessionSummary(session)) + '</span>' +
    (pendingSummary ? '<div class="session-pending-summary">' + escapeHtml(pendingSummary) + '</div>' : '') +
    '<span class="hi-stats">' + pips + '</span>' +
    '<span class="hi-strip">' + renderHistoryStrip(session) + '</span>' +
  '</div>';
}

function historySessionDeleteButtonHtml(session, label, navigationBusy) {
  return '<button type="button" class="session-row-delete icon-button" data-delete-session-id="' + escapeHtml(session.sessionId) + '" data-delete-session-label="' + escapeHtml(label) + '" data-delete-session-annotations="' + escapeHtml(String(session.itemsCount || 0)) + '" data-delete-session-screens="' + escapeHtml(String(session.screensCount || 0)) + '" aria-label="Delete session" title="Delete session"' + (navigationBusy ? ' disabled' : '') + '>' +
    '<svg viewBox="0 0 24 24" aria-hidden="true" fill="none" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">' +
      '<path d="M3 6h18M8 6V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2M6 6l1 14a2 2 0 0 0 2 2h6a2 2 0 0 0 2-2l1-14" stroke="currentColor"/>' +
    '</svg>' +
  '</button>';
}

function bindHistorySessionRowEvents(root) {
  root.querySelectorAll('.session-row').forEach(row => {
    row.addEventListener('click', event => {
      if (event.target.closest('[data-delete-session-id]')) return;
      openSession(row.dataset.sessionId)
        .then(() => closeHistoryDrawer({ returnFocus: false }))
        .catch(showError);
    });
    row.addEventListener('keydown', event => {
      if (event.target.closest('[data-delete-session-id]')) return;
      if (event.key === 'Enter' || event.key === ' ') {
        event.preventDefault();
        openSession(row.dataset.sessionId)
          .then(() => closeHistoryDrawer({ returnFocus: false }))
          .catch(showError);
      }
    });
  });
  root.querySelectorAll('[data-delete-session-id]').forEach(button => {
    button.addEventListener('click', event => {
      event.stopPropagation();
      deleteHistorySession(button.dataset.deleteSessionId, {
        sessionLabel: button.dataset.deleteSessionLabel,
        annotationCount: Number(button.dataset.deleteSessionAnnotations || 0),
        screenCount: Number(button.dataset.deleteSessionScreens || 0),
      }).catch(showError);
    });
  });
}
//#endregion historySessionRow.js

//#region history.js
// @requires state.js, draftWorkspace.js, annotations.js, historyPendingDedupe.js, domain/consoleEvents.js, boundaryTriggers.js, draftUseCases.js, editorState.js, boundaryDialogVariants.js, historySessionRow.js
            function sessionOrdinalLookup(sessions) {
              const ordinalBySessionId = new Map();
              stableHistorySessions(sessions)
                .forEach((session, index) => {
                  ordinalBySessionId.set(session.sessionId, index + 1);
                });
              return ordinalBySessionId;
            }

            function stableHistorySessions(sessions) {
              return [...(sessions || [])].sort((left, right) =>
                (left.createdAtEpochMillis || 0) - (right.createdAtEpochMillis || 0) ||
                String(left.sessionId || '').localeCompare(String(right.sessionId || ''))
              );
            }

            function formatSessionLabel(session, ordinal) {
              const safeOrdinal = Math.max(1, Number(ordinal || 1));
              return 'Session ' + safeOrdinal;
            }

            function formatSessionSummary(session) {
              const screens = Number(session?.screensCount || 0);
              const screensLabel = screens > 0 ? countLabel(screens, 'screen', 'screens') + ' · ' : '';
              return screensLabel + formatHistoryDate(session.updatedAtEpochMillis);
            }

            function pendingHistoryItemsForSession(session) {
              if (draftFlow() && state.session?.sessionId === session?.sessionId) {
                return dedupePendingHistoryItemsForSession(session, draftItemList(), draftWorkspace?.workspaceId);
              }
              return historyRecoveryItemsForSession(session);
            }

            function historyRecoveryItemsForSession(session) {
              const sessionId = session?.sessionId;
              if (!sessionId) return [];
              try {
                const storage = createBrowserDraftPorts().storage;
                return newestDedupedHistoryRecoveryItems(session, storage.loadWorkspacesForSession(sessionId));
              } catch (_) {
                return [];
              }
            }

            function pendingHistorySummaryForSession(session) {
              const items = pendingHistoryItemsForSession(session);
              const summary = draftRecoverySummary(items);
              if (!summary.total) return '';
              const parts = [];
              if (summary.commented) parts.push(countLabel(summary.commented, 'draft comment', 'draft comments'));
              if (summary.pinOnly) parts.push(countLabel(summary.pinOnly, 'pin without comment', 'pins without comments'));
              return parts.join(' · ');
            }

            function historyOpenCount(session) {
              const pending = pendingHistoryItemsForSession(session);
              return (session.unresolvedItemsCount || 0) + pending.filter(item => annotationStatus(item) !== 'resolved').length;
            }

            function historyDoneCount(session) {
              const pending = pendingHistoryItemsForSession(session);
              const persistedDone = Math.max(0, (session.itemsCount || 0) - (session.unresolvedItemsCount || 0));
              return persistedDone + pending.filter(item => annotationStatus(item) === 'resolved').length;
            }

            function renderHistoryStrip(session) {
              const open = historyOpenCount(session);
              const done = historyDoneCount(session);
              const total = open + done;
              if (!total) return '<span class="hi-strip-cell empty"></span>';
              return [
                ...Array.from({ length: open }, () => '<span class="hi-strip-cell"></span>'),
                ...Array.from({ length: done }, () => '<span class="hi-strip-cell done"></span>')
              ].join('');
            }

            function firstLine(value) {
              return text(value).split(/\r?\n/)[0] || '(No comment)';
            }

            function formatItemLabel(item, index) {
              const number = item.sequenceNumber ?? (index + 1);
              return '#' + number + ' ' + firstLine(item.comment || '(No comment)');
            }

            function formatSavedEvidenceItemLabel(item, index) {
              const number = item.sequenceNumber ?? (index + 1);
              return '#' + number + ' ' + firstLine(item.comment || '(No comment)');
            }

            function findScreen(screenId) {
              return (state.session?.screens || []).find(screen => screen.screenId === screenId) || null;
            }


            function selectedHistorySummary() {
              const sessionId = state.session?.sessionId;
              if (!sessionId) return null;
              return (state.sessionSummaries || []).find(session => session.sessionId === sessionId) || null;
            }

            function displayedSessionId() {
              return state.session?.sessionId || draftWorkspace?.context?.sessionId || null;
            }

            function isClosedSession(session) {
              return String(session?.status || '').toLowerCase() === 'closed';
            }

            function clearDisplayedSessionState() {
              pendingRecovery = null;
              resetComposer();
              clearPreview();
              setConsoleSession(null);
            }

            let sessionNavigationInFlight = false;
            let pendingSessionNavigationId = null;

            function isSessionNavigationInFlight() {
              return sessionNavigationInFlight;
            }

            function toolbarAnnotationCounts() {
              if (draftFlow()) {
                const pending = draftItemList();
                return {
                  open: pending.filter(item => annotationStatus(item) !== 'resolved').length,
                  resolved: pending.filter(item => annotationStatus(item) === 'resolved').length
                };
              }
              const annotations = toolbarAnnotations();
              return {
                open: annotations.filter(item => annotationStatus(item) !== 'resolved').length,
                resolved: annotations.filter(item => annotationStatus(item) === 'resolved').length
              };
            }

            function toolbarOpenCount() {
              return toolbarAnnotationCounts().open;
            }

            function toolbarResolvedCount() {
              return toolbarAnnotationCounts().resolved;
            }

            function selectedAnnotation() {
              if (draftFocusIndex() == null) return null;
              return draftItemList()[draftFocusIndex()] || null;
            }

            function sourceHintLabel(item) {
              return (item.sourceCandidates || []).length ? 'Source hint available' : 'No source hint';
            }

            function hasActiveHistorySessionForAnnotating() {
              return Boolean(
                state.session &&
                state.session.status !== 'closed' &&
                (state.sessionSummaries || []).some(session =>
                  session.sessionId === state.session.sessionId &&
                  session.status !== 'closed'
                )
              );
            }

            async function ensureSessionForAnnotating() {
              if (hasActiveHistorySessionForAnnotating()) return;
              if (!requirePendingRecoveryChoiceBeforeSessionChange()) {
                throw new Error('Recover, recapture, or discard unsaved annotations before changing sessions.');
              }
              resetComposer();
              clearPreview();
	              setConsoleSession(await withMutationLock(() => requestJson('/api/session/open', {
	                method: 'POST',
	                headers: { 'Content-Type': 'application/json' },
	                body: JSON.stringify({ newSession: true })
	              })));
              await refreshSessions();
            }

            async function enterAnnotateMode() {
              if (!requirePendingRecoveryChoiceBeforeSessionChange()) {
                showStatus('Resolve the recovered draft first, then try Start annotating again.', { variant: 'warn', durationMs: 3500 });
                return;
              }
              await ensureSessionForAnnotating();
              if (!draftFlow()) {
                await startDraftAnnotationFlow();
              } else {
                toolMode.enterAnnotate();
                renderCurrentSessionList();
                renderPreviewOnly();
                renderInspectorRegion();
              }
            }

            async function enterNewHistoryAnnotateMode() {
              if (toolMode.getState().newHistoryAnnotateModeStarting) return;
              const wasAnnotating = toolMode.isAnnotateMode();
              toolMode.setNewHistoryAnnotateModeStarting(true);
              renderCurrentSessionList();
              try {
                const openedNewSession = await newSession();
                if (!openedNewSession) {
                  if (!wasAnnotating) toolMode.enterSelect();
                  render();
                  return;
                }
                scrollActiveHistoryItemIntoView();
                await enterAnnotateMode();
                scrollActiveHistoryItemIntoView();
              } finally {
                toolMode.setNewHistoryAnnotateModeStarting(false);
                renderCurrentSessionList();
              }
            }

            function scrollActiveHistoryItemIntoView() {
              const activeRow = sessions.querySelector('.session-row.is-active');
              activeRow?.scrollIntoView({ block: 'nearest' });
            }

            function syncHistoryDrawerState() {
              if (!historyToggleButton || !historyDrawerScrim) return;
              const open = toolMode.getState().historyDrawerOpen;
              if (open) {
                document.body.dataset.historyDrawerOpen = 'true';
              } else {
                delete document.body.dataset.historyDrawerOpen;
              }
              historyToggleButton.setAttribute('aria-expanded', String(open));
            }

            function openHistoryDrawer() {
              toolMode.setHistoryDrawer(true);
              syncHistoryDrawerState();
              document.getElementById('historyPanel')?.focus({ preventScroll: true });
            }

            function closeHistoryDrawer(options = {}) {
              const wasOpen = toolMode.getState().historyDrawerOpen;
              toolMode.setHistoryDrawer(false);
              syncHistoryDrawerState();
              if (wasOpen && options.returnFocus !== false) historyToggleButton?.focus({ preventScroll: true });
            }

            // Wraps the history module's global listeners so the boot
            // controller (main.js) can dispose them via __fixthisDisposers.
            // Per-row listeners attached inside renderSessionsListFromPayload
            // re-attach on every render and are out of scope for dispose().
            function initHistory({
              document,
              historyToggleButton,
              historyDrawerScrim,
              openHistoryDrawer,
              closeHistoryDrawer,
              syncHistoryDrawerState,
              toolMode,
            }) {
              const handlers = [];
              function on(target, type, fn) {
                if (!target) return;
                target.addEventListener(type, fn);
                handlers.push([target, type, fn]);
              }
              on(historyToggleButton, 'click', openHistoryDrawer);
              const scrimHandler = () => closeHistoryDrawer();
              on(historyDrawerScrim, 'click', scrimHandler);
              const keydownHandler = (event) => {
                if (event.key === 'Escape' && toolMode.getState().historyDrawerOpen) {
                  event.preventDefault();
                  closeHistoryDrawer();
                }
              };
              on(document, 'keydown', keydownHandler);
              syncHistoryDrawerState();
              return {
                dispose() {
                  for (const [target, type, fn] of handlers) {
                    target.removeEventListener(type, fn);
                  }
                  handlers.length = 0;
                },
              };
            }
            __fixthisDisposers.push(initHistory({
              document,
              historyToggleButton,
              historyDrawerScrim,
              openHistoryDrawer,
              closeHistoryDrawer,
              syncHistoryDrawerState,
              toolMode,
            }));

            function historyStartAnnotatingItemHtml() {
              if (toolMode.getState().newHistoryAnnotateModeStarting || isSessionNavigationInFlight()) return '';
              return '<button type="button" class="history-item history-add-row" data-start-new-history-annotating aria-label="Start annotating">' +
                '<svg viewBox="0 0 24 24" fill="none" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M12 5v14"/><path d="M5 12h14"/></svg>' +
              '</button>';
            }


            function renderSessionsListFromPayload(sessionSummaries) {
              state.sessionSummaries = sessionSummaries;
              const activeId = state.session?.sessionId;
              const navigationBusy = isSessionNavigationInFlight();
              const activeSummaries = sessionSummaries.filter(session => session.status !== 'closed');
              const ordinalBySessionId = sessionOrdinalLookup(activeSummaries);
              const renderedActiveSummaries = stableHistorySessions(activeSummaries);
              sessionCount.textContent = String(activeSummaries.length);
              const renderedSessions = renderedActiveSummaries.map((session, index) => {
                const open = historyOpenCount(session);
                const done = historyDoneCount(session);
                const label = formatSessionLabel(session, ordinalBySessionId.get(session.sessionId) || index + 1);
                const pendingSummary = pendingHistorySummaryForSession(session);
                const pips = [
                  open > 0 ? '<span class="hi-pip open">' + escapeHtml(countLabel(open, 'open', 'open')) + '</span>' : '',
                  done > 0 ? '<span class="hi-pip done">' + escapeHtml(countLabel(done, 'resolved', 'resolved')) + '</span>' : '',
                ].join('');
                const busy = navigationBusy && (session.sessionId === activeId || session.sessionId === pendingSessionNavigationId);
                return historySessionRowHtml({
                  session,
                  label,
                  pendingSummary,
                  pips,
                  activeId,
                  busy,
                  navigationBusy,
                });
              }).join('');
              sessions.innerHTML = renderedSessions
                ? renderedSessions + historyStartAnnotatingItemHtml()
                : historyStartAnnotatingItemHtml() + emptySessionsHtml();
              bindHistorySessionRowEvents(document);
              document.querySelectorAll('[data-start-new-history-annotating]').forEach(button => {
                button.addEventListener('click', () => enterNewHistoryAnnotateMode().catch(showError));
              });
            }

            function applySessionSummaryFromPayload(summary) {
              if (!summary || !summary.sessionId) return state.sessionSummaries || [];
              const existing = state.sessionSummaries || [];
              const found = existing.some(session => session.sessionId === summary.sessionId);
              const next = found
                ? existing.map(session => session.sessionId === summary.sessionId ? summary : session)
                : [summary, ...existing];
              renderSessionsListFromPayload(next);
              return next;
            }

            function renderSessionsList() {
              const activeId = state.session?.sessionId;
              const navigationInFlight = isSessionNavigationInFlight();
              document.querySelectorAll('.session-row').forEach(row => {
                const busy = navigationInFlight && (row.dataset.sessionId === activeId || row.dataset.sessionId === pendingSessionNavigationId);
                row.classList.toggle('is-active', row.dataset.sessionId === activeId);
                row.classList.toggle('is-busy', busy);
                row.setAttribute('aria-busy', busy ? 'true' : 'false');
                row.setAttribute('aria-disabled', navigationInFlight ? 'true' : 'false');
                row.querySelectorAll('[data-delete-session-id]').forEach(button => {
                  button.disabled = navigationInFlight;
                });
              });
            }

            function renderCurrentSessionList() {
              renderSessionsListFromPayload(state.sessionSummaries || []);
            }

            // Sync sidebar summaries and the active session in lockstep so the panel/toolbar
            // (driven by state.session) cannot drift behind the sidebar (driven by summaries).
            // Both endpoints fetched in parallel; if one fails the call rejects as before.
            async function refreshSessions() {
              const previousSessionId = state.session?.sessionId || null;
              const [response, currentSession] = await Promise.all([
                requestJson('/api/sessions'),
                requestJson('/api/session'),
              ]);
              const nextSessionId = currentSession?.sessionId || null;
              if (previousSessionId !== nextSessionId) clearPreview();
              setConsoleSession(currentSession || null);
              renderSessionsListFromPayload(response.sessions || []);
              return response.sessions || [];
            }

            async function refreshSessionsWhenEventsDisconnected() {
              if (isConsoleEventsConnected() || wasConsoleEventsRecentlyConnected()) return state.sessionSummaries || [];
              return refreshSessions();
            }

            async function refresh() {
              error.textContent = '';
              await refreshSessions();
              await refreshDevices();
              await refreshConnection();
              loadPendingRecoveryForCurrentSession();
              render();
            }

            async function openSession(sessionId) {
              if (!sessionId) return;
              error.textContent = '';
              if (sessionId === state.session?.sessionId) {
                renderSessionsList();
                return;
              }
              if (sessionNavigationInFlight) {
                pendingSessionNavigationId = sessionId;
                renderSessionsList();
                return;
              }
              sessionNavigationInFlight = true;
              pendingSessionNavigationId = null;
              renderSessionsList();
              try {
                resolveTrigger(Trigger.SESSION_SWITCH, {
                  state: deriveEditorState(currentDraftWorkspace(), draftSelection(), null),
                  targetSessionId: sessionId,
                }, {
                  silentDiscard: clearSelection,
                  showToast: (text) => showStatus(text, { variant: 'info' }),
                  openBoundaryDialog: () => {},
                  preserve: () => {},
                });
                if (await resolvePendingBeforeBoundary('open-session', sessionId) !== 'continue') return;
                bumpSessionMutationGeneration();
                stopLivePreviewPolling();
                resetComposer(true, false);
                clearPreview();
	                setConsoleSession(await withMutationLock(() => requestJson('/api/session/open', {
	                  method: 'POST',
	                  headers: { 'Content-Type': 'application/json' },
	                  body: JSON.stringify({ sessionId: sessionId })
	                })));
                renderCurrentSessionList();
                renderInspectorRegion();
                await refresh();
                if (!latestPersistedScreen() && shouldAutoFetchPreview()) {
                  await refreshPreview();
                }
                startLivePreviewPolling();
              } finally {
                sessionNavigationInFlight = false;
                const queuedSessionId = pendingSessionNavigationId;
                pendingSessionNavigationId = null;
                renderCurrentSessionList();
                if (queuedSessionId && queuedSessionId !== state.session?.sessionId) await openSession(queuedSessionId);
              }
            }

            async function newSession() {
              error.textContent = '';
              if (sessionNavigationInFlight) return false;
              if (await resolvePendingBeforeBoundary('new-session') !== 'continue') return false;
              bumpSessionMutationGeneration();
              resetComposer();
              clearPreview();
	              setConsoleSession(await withMutationLock(() => requestJson('/api/session/open', {
	                method: 'POST',
	                headers: { 'Content-Type': 'application/json' },
	                body: JSON.stringify({ newSession: true })
	              })));
              await refresh();
              startLivePreviewPolling();
              return true;
            }

            async function closeSession() {
              error.textContent = '';
              if (!state.session) return;
              if (await resolvePendingBeforeBoundary('close-session', state.session.sessionId) !== 'continue') return;
              const sessionId = state.session.sessionId;
              bumpSessionMutationGeneration();
              await withMutationLock(() => requestJson('/api/session/close', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ sessionId: sessionId })
              }));
              resetComposer();
              clearPreview();
              setConsoleSession(null);
              await refreshSessions();
              render();
              await refreshDevices();
            }

            async function deleteHistorySession(sessionId, options = {}) {
              error.textContent = '';
              if (!sessionId) return;
              if (sessionNavigationInFlight) return;
              const deleteContext = {
                currentSessionName: options.sessionLabel || 'this session',
                annotationCount: options.annotationCount ?? 0,
                screenCount: options.screenCount ?? 0,
              };
              const hasDraftForThisSession = draftWorkspace?.context?.sessionId === sessionId
                && draftItemList().length > 0;
              if (hasDraftForThisSession) {
                if (await resolvePendingBeforeBoundary('delete-session', sessionId, {
                  ...deleteContext,
                  annotationCount: deleteContext.annotationCount + draftItemList().length,
                }) !== 'continue') return;
              } else {
                const choice = await promptBoundaryDialogChoice('sessionDelete', deleteContext);
                if (choice !== 'confirm') return;
              }
              const isDisplayedSession = () => state.session?.sessionId === sessionId;
              const hasDisplayedDraftForDeletedSession = () => draftWorkspace?.context?.sessionId === sessionId;
              const hasPendingRecoveryForDeletedSession = () =>
                (pendingRecovery?.sessionId || pendingRecovery?.context?.sessionId) === sessionId;
              const wasDisplayedSession = isDisplayedSession();
              const wasDisplayedDraft = hasDisplayedDraftForDeletedSession();
              const hadPendingRecovery = hasPendingRecoveryForDeletedSession();
              bumpSessionMutationGeneration();
              await withMutationLock(() => requestJson('/api/session/close', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ sessionId: sessionId })
              }));
              createBrowserDraftPorts().storage.deleteWorkspacesForSession(sessionId);
              if (hadPendingRecovery) pendingRecovery = null;
              if (wasDisplayedSession || wasDisplayedDraft) {
                clearDisplayedSessionState();
              }
              await refreshSessions();
              render();
              await refreshDevices();
            }

            async function clearLocalDraft() {
              error.textContent = '';
              if (!draftFlow() && !pendingRecoveryItems(pendingRecovery).length) return;
              const accepted = await promptBoundaryDialogChoice('clearLocalDraft', {
                itemCount: draftWorkspaceItems(draftWorkspace).length || pendingRecoveryItems(pendingRecovery).length,
              });
              if (accepted !== 'confirm') return;
              deleteCurrentDraftWorkspaceStorage();
              if (pendingRecovery?.schemaVersion === 2) {
                createBrowserDraftPorts().storage.deleteWorkspace(
                  pendingRecovery.sessionId || pendingRecovery.context?.sessionId,
                  pendingRecovery.workspaceId,
                );
              }
              pendingRecovery = null;
              replaceDraftWorkspace(createEmptyDraftWorkspace());
              clearSelection();
              renderPendingRecoveryBanner();
              render();
            }

            async function clearServerDrafts() {
              error.textContent = '';
              const sessionId = state.session?.sessionId;
              if (!sessionId) return;
              if (await resolvePendingBeforeBoundary('clear-server-drafts', sessionId) !== 'continue') return;
              const accepted = await promptBoundaryDialogChoice('clearServerDrafts', {
                itemCount: savedEvidenceItems().filter((item) => item.delivery !== 'sent').length,
              });
              if (accepted !== 'confirm') return;
              await withMutationLock(() => requestJson('/api/items/draft?sessionId=' + encodeURIComponent(sessionId), { method: 'DELETE' }));
              clearSelection();
              await refresh();
            }
//#endregion history.js

//#region previewStaleness.js
// @requires state.js
// previewStaleness.js — SIF-5: pure decision helper for time-based and
// disconnect-based preview staleness. A frozen preview becomes stale when
// either (a) it is older than MAX_PREVIEW_AGE_MS, or (b) the bridge is not
// in the "connected" state. The status-tick site in main.js / connection.js
// is responsible for calling evaluateStale on each refresh and writing the
// result back into state.preview.stale.
//
// NOTE: This file is intentionally separate from staleness.js, which handles
// build-epoch / protocol-version drift between the server JAR and the bundled
// console assets — an unrelated concern.

const MAX_PREVIEW_AGE_MS = 30000;

function evaluateStale(state, now) {
  const frozenAt = state && state.preview && state.preview.frozenAtEpochMillis;
  if (!frozenAt) return false;
  const age = now - frozenAt;
  if (age > MAX_PREVIEW_AGE_MS) return true;
  const connection = state && state.bridgeStatus && state.bridgeStatus.connection;
  if (connection !== 'connected') return true;
  return false;
}
//#endregion previewStaleness.js

//#region runtimeEvidence.js
// @requires api.js, state.js
            const RuntimeEvidencePresets = ['baseline', 'logs', 'memory', 'performance'];
            const RuntimeEvidencePolicies = ['auto_on_handoff', 'manual', 'off'];

            function runtimeEvidenceEscapeHtml(value) {
              return String(value ?? '').replace(/[&<>"']/g, char => ({
                '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#039;'
              })[char]);
            }

            function runtimeEvidenceWarningLabel(value) {
              return String(value || '').replaceAll('_', ' ');
            }

            function runtimeEvidenceStatusModel(value) {
              const allowed = ['collecting', 'complete', 'partial', 'failed', 'unsupported', 'disabled'];
              const status = allowed.includes(value?.status) ? value.status : 'unsupported';
              return { status, label: 'Diagnostics: ' + (status === 'disabled' ? 'off' : status) };
            }

            function renderRuntimeEvidenceRows(value) {
              const rows = [
                ['Captured', value?.capturedAtEpochMillis ? new Date(value.capturedAtEpochMillis).toLocaleTimeString() : null],
                ['Proximity', value?.proximity],
                ['Type', value?.type],
                ['Summary', value?.summary],
                ['Artifact', value?.artifactPath],
                ['Reason', value?.failureReason],
                ...(value?.warnings || []).slice(0, 4).map((warning, index) => ['Warning ' + (index + 1), warning]),
              ].filter(row => row[1]).map(row => row.map(entry => runtimeEvidenceWarningLabel(entry).slice(0, 500)));
              return rows.map(row => '<span>' + runtimeEvidenceEscapeHtml(row[0]) + '</span><strong>' +
                runtimeEvidenceEscapeHtml(row[1]) + '</strong>').join('');
            }

            function createRuntimeEvidenceController(ports) {
              const captures = ports.captureState || new Map();
              const captureSeq = new Map();
              const policySeq = new Map();
              const keyOf = (sessionId, itemId) => sessionId + '\u0000' + itemId;
              const next = (map, key) => (map.set(key, (map.get(key) || 0) + 1), map.get(key));
              const current = input => {
                const session = ports.activeSession();
                const item = (session?.items || []).find(candidate => candidate.itemId === input.itemId);
                return session?.sessionId === input.sessionId && item?.screenId === input.screenId;
              };
              const stale = (key, generation, input) => {
                if (captureSeq.get(key) !== generation) return true;
                if (current(input)) return false;
                captures.delete(key);
                return true;
              };

              async function collect(input) {
                if (!RuntimeEvidencePresets.includes(input.preset)) throw new Error('Unknown runtime evidence preset');
                const key = keyOf(input.sessionId, input.itemId);
                const generation = next(captureSeq, key);
                captures.set(key, { status: 'collecting', generation, screenId: input.screenId });
                ports.render?.();
                try {
                  const result = await ports.request('/api/items/' + encodeURIComponent(input.itemId) + '/runtime-evidence/collect', {
                    method: 'POST', headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ sessionId: input.sessionId, preset: input.preset }),
                  });
                  if (stale(key, generation, input)) return null;
                  const safe = {
                    status: result?.status || (result?.skippedReason ? 'unsupported' : 'failed'),
                    attachmentIds: [...(result?.attachmentIds || [])],
                    linkedItemIds: [...(result?.linkedItemIds || [])],
                    warnings: [...(result?.warnings || [])].slice(0, 4),
                    failureReason: result?.failureReason || null,
                    skippedReason: result?.skippedReason || null,
                    generation,
                    screenId: input.screenId,
                  };
                  captures.set(key, safe);
                  return safe;
                } catch (error) {
                  if (stale(key, generation, input)) return null;
                  captures.set(key, { status: 'failed', generation, screenId: input.screenId, failureReason: error?.error || 'collection_failed' });
                  throw error;
                } finally {
                  ports.render?.();
                }
              }

              async function updatePolicy(policy) {
                if (!RuntimeEvidencePolicies.includes(policy)) throw new Error('Unknown runtime evidence policy');
                const sessionId = ports.activeSession()?.sessionId;
                if (!sessionId) throw new Error('No active feedback session');
                const generation = next(policySeq, sessionId);
                let updated;
                try {
                  updated = await ports.request('/api/sessions/' + encodeURIComponent(sessionId) + '/runtime-evidence-policy', {
                    method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ policy }),
                  });
                } catch (error) {
                  if (policySeq.get(sessionId) !== generation || ports.activeSession()?.sessionId !== sessionId) return null;
                  throw error;
                }
                if (policySeq.get(sessionId) !== generation || ports.activeSession()?.sessionId !== sessionId) return null;
                ports.applySession(updated);
                ports.render?.();
                return updated;
              }

              const stateFor = (itemId, sessionId = ports.activeSession()?.sessionId) =>
                sessionId ? captures.get(keyOf(sessionId, itemId)) || null : null;
              return { collect, stateFor, updatePolicy };
            }

            let browserRuntimeEvidenceController;

            function runtimeEvidenceController() {
              return browserRuntimeEvidenceController ||= createRuntimeEvidenceController({
                activeSession: () => state.session,
                request: requestJson,
                applySession: setConsoleSession,
                captureState: state.runtimeEvidenceByItem,
                render: () => renderInspectorRegion(),
              });
            }

            function collectRuntimeEvidenceForItem(item, preset = 'baseline') {
              const sessionId = state.session?.sessionId;
              if (!sessionId || !item?.itemId || !item?.screenId) return Promise.reject(new Error('Annotation context is unavailable'));
              if (state.session.runtimeEvidencePolicy === 'off') return Promise.resolve(null);
              return runtimeEvidenceController().collect({ sessionId, itemId: item.itemId, screenId: item.screenId, preset });
            }

            function updateRuntimeEvidencePolicy(policy) {
              return runtimeEvidenceController().updatePolicy(policy);
            }

            function runtimeEvidenceAttachmentsForItem(item) {
              const ids = new Set(item?.runtimeEvidenceIds || []);
              return (state.session?.runtimeEvidence || []).filter(value => ids.has(value.evidenceId))
                .sort((left, right) => (right.capturedAtEpochMillis || 0) - (left.capturedAtEpochMillis || 0));
            }

            function runtimeEvidenceSectionHtml(item) {
              const attachments = runtimeEvidenceAttachmentsForItem(item);
              const current = runtimeEvidenceController().stateFor(item?.itemId) || attachments[0];
              const off = state.session?.runtimeEvidencePolicy === 'off';
              const model = off ? runtimeEvidenceStatusModel({ status: 'disabled' }) : (current && runtimeEvidenceStatusModel(current));
              const collecting = model?.status === 'collecting';
              const label = collecting ? 'Capturing diagnostics…' : ((attachments.length || current) ? 'Capture again' : 'Capture diagnostics');
              const entries = attachments.slice(0, 4).map(value => {
                const status = runtimeEvidenceStatusModel(value).status;
                return '<div class="runtime-evidence-entry" data-status="' + runtimeEvidenceEscapeHtml(status) + '"><strong>' +
                  runtimeEvidenceEscapeHtml(runtimeEvidenceWarningLabel(value.type)) + ' · ' + runtimeEvidenceEscapeHtml(status) +
                  '</strong><div class="evidence-grid">' + renderRuntimeEvidenceRows(value) + '</div></div>';
              }).join('');
              const pendingRows = current && !attachments.length ? '<div class="evidence-grid">' + renderRuntimeEvidenceRows(current) + '</div>' : '';
              return '<section class="annotation-section runtime-evidence-section" role="status" aria-live="polite"><div class="runtime-evidence-heading"><h3>Diagnostics</h3>' +
                (model ? '<span class="runtime-evidence-status" data-status="' + model.status + '">' + model.label + '</span>' : '') + '</div>' +
                (off ? '<p class="runtime-evidence-help">Diagnostics are Off for this session.</p>' : '') + pendingRows + entries +
                '<button id="collectRuntimeEvidenceButton" type="button" aria-busy="' + collecting + '"' + (collecting || off ? ' disabled' : '') + '>' + label + '</button></section>';
            }

            function bindRuntimeEvidenceCollection(root, item) {
              root.querySelector('#collectRuntimeEvidenceButton')?.addEventListener('click', () => {
                collectRuntimeEvidenceForItem(item).then(result => {
                  if (result) showSuccess('Diagnostics captured', 2e3);
                }).catch(showError);
              });
            }

            function renderRuntimeEvidencePolicyControl() {
              const control = document.getElementById('runtimeEvidencePolicy');
              if (!control) return;
              control.disabled = !state.session?.sessionId || state.session.status === 'closed';
              control.value = state.session?.runtimeEvidencePolicy || 'manual';
            }
//#endregion runtimeEvidence.js

//#region domain/targetReliabilityViewModel.js
// @requires (none)
function targetReliabilityBadgeModel(targetReliability) {
  const confidence = String(targetReliability?.confidence || 'unknown').toLowerCase();
  const score = Number(targetReliability?.score);
  const scoreLabel = Number.isFinite(score) ? `${Math.round(score * 100)}%` : '';
  if (confidence === 'high') return { confidence, label: 'Reliability High', tone: 'good', scoreLabel };
  if (confidence === 'medium') return { confidence, label: 'Reliability Medium', tone: 'warn', scoreLabel };
  if (confidence === 'low') return { confidence, label: 'Reliability Low', tone: 'bad', scoreLabel };
  return { confidence: 'unknown', label: 'Reliability Unknown', tone: 'muted', scoreLabel: '' };
}
