// @requires state.js, api.js, boundaryDialogVariants.js
            const BLOCKED_SUFFIX = {
              screenOff: 'Screen off',
              locked: 'Locked',
              background: 'In background',
              pictureInPicture: 'PiP',
              unresponsive: 'Unresponsive',
              noComposeUi: 'No Compose UI',
            };

            function decorateConnectionLabel(baseLabel, reason) {
              if (!reason) return baseLabel;
              const suffix = BLOCKED_SUFFIX[reason];
              return suffix ? `${baseLabel} · ${suffix}` : baseLabel;
            }

            function shortenDeviceSerial(serial) {
              const raw = String(serial || '').trim();
              if (!raw) return '';
              const withoutServiceSuffix = raw.split('._adb-tls-connect._tcp')[0];
              if (withoutServiceSuffix.startsWith('adb-')) return withoutServiceSuffix.substring(4);
              if (withoutServiceSuffix.length <= 24) return withoutServiceSuffix;
              return withoutServiceSuffix.slice(0, 10) + '...' + withoutServiceSuffix.slice(-6);
            }

            function deviceLabel(device) {
              if (!device) return 'No device';
              return device.label || device.model || device.deviceName || device.product || shortenDeviceSerial(device.serial) || 'Unknown device';
            }

            function deviceDetail(device) {
              if (!device) return 'No device';
              if (device.state === 'device') return 'connected';
              return (device.state || 'unknown') + ' · unavailable';
            }

            function deviceOptionLabel(device) {
              return deviceLabel(device) + ' - ' + deviceDetail(device);
            }

            function setDeviceUiState(uiState, device = null) {
              deviceControl.dataset.connectionState = uiState;
              deviceName.textContent = device ? deviceLabel(device) : 'No device';
              const baseLabel = DeviceStateCopy[uiState];
              const reason = uiState === DeviceUiState.CONNECTED
                ? (state.connection?.interactionBlockedReason || null)
                : null;
              deviceConnectionState.textContent = decorateConnectionLabel(baseLabel, reason);
              deviceStatus.textContent = deviceName.textContent + ' - ' + deviceConnectionState.textContent;
            }


            function deviceBySerial(devices, serial) {
              if (!serial) return null;
              return (devices || []).find(device => device.serial === serial) || null;
            }

            function renderDeviceList(payload) {
              const devices = payload.devices || [];
              state.devices = devices;
              const previousSelectedDeviceSerial = state.selectedDeviceSerial;
              devicePicker.innerHTML = '';

              if (!devices.length) {
                const selectedSerial = null;
                if (previousSelectedDeviceSerial !== selectedSerial) {
                  bumpSessionMutationGeneration();
                  clearPreview();
                  renderPreviewOnly();
                }
                state.selectedDeviceSerial = selectedSerial;
                const option = document.createElement('option');
                option.value = '';
                option.textContent = 'No devices available';
                devicePicker.appendChild(option);
                devicePicker.disabled = true;
                setDeviceUiState(DeviceUiState.NONE);
                return;
              }

              const selectedSerialFromPayload = payload.selectedSerial || null;
              const selected = devices.find(device => device.selected || device.serial === selectedSerialFromPayload) || null;
              devicePicker.disabled = false;

              if (!selected) {
                const option = document.createElement('option');
                option.value = '';
                option.textContent = 'Select device...';
                option.disabled = true;
                option.selected = true;
                devicePicker.appendChild(option);
              }

              devices.forEach(device => {
                const option = document.createElement('option');
                option.value = device.serial;
                option.textContent = deviceOptionLabel(device);
                option.disabled = device.state !== 'device';
                option.selected = Boolean(device.selected) || device.serial === selectedSerialFromPayload;
                devicePicker.appendChild(option);
              });

              const selectedSerial = selected && selected.state === 'device' ? selected.serial : null;
              if (previousSelectedDeviceSerial !== selectedSerial) {
                bumpSessionMutationGeneration();
                clearPreview();
                renderPreviewOnly();
              }
              state.selectedDeviceSerial = selectedSerial;

              if (!selected) {
                setDeviceUiState(DeviceUiState.NONE);
              } else if (selected.state === 'device') {
                setDeviceUiState(DeviceUiState.CONNECTED, selected);
              } else {
                setDeviceUiState(DeviceUiState.UNAVAILABLE, selected);
              }
            }

            async function refreshDevices() {
              if (state.selectedDeviceSerial) {
                setDeviceUiState(DeviceUiState.CONNECTING, deviceBySerial(state.devices, state.selectedDeviceSerial));
              }
              let payload = await requestJson('/api/devices');
              const devices = payload.devices || [];
              const connectedDevices = (payload.devices || []).filter(device => device.state === 'device');
              if (!payload.selectedSerial && devices.length === 1 && connectedDevices.length === 1) {
                setDeviceUiState(DeviceUiState.CONNECTING, connectedDevices[0]);
                bumpSessionMutationGeneration();
                payload = await requestJson('/api/device/select', {
                  method: 'POST',
                  headers: { 'Content-Type': 'application/json' },
                  body: JSON.stringify({ serial: connectedDevices[0].serial })
                });
              }
              renderDeviceList(payload);
            }

            async function selectDevice() {
              const option = devicePicker.selectedOptions[0];
              if (!option || !option.value) return;
              if (option.disabled) {
                showStatus('That device is not selectable right now. Reconnect or pick another one.', { variant: 'warn', durationMs: 3000 });
                return;
              }
              setDeviceUiState(DeviceUiState.CONNECTING, deviceBySerial(state.devices, option.value));
              bumpSessionMutationGeneration();
              clearPreview();
              try {
                renderDeviceList(await requestJson('/api/device/select', {
                  method: 'POST',
                  headers: { 'Content-Type': 'application/json' },
                  body: JSON.stringify({ serial: option.value })
                }));
                startHeartbeatPolling();
                await refreshConnection();
                if (state.session && userConnectionState(state.connection.current) === 'ready') {
                  await refreshPreview();
                  startLivePreviewPolling();
                }
              } catch (cause) {
                state.selectedDeviceSerial = null;
                stopHeartbeatPolling();
                stopLivePreviewPolling();
                setDeviceUiState(DeviceUiState.UNAVAILABLE, deviceBySerial(state.devices, option.value) || { serial: option.value });
                throw cause;
              }
            }

            function currentDeviceName() {
              const selected = deviceBySerial(state.devices, state.selectedDeviceSerial);
              return deviceLabel(selected || null);
            }

            async function forgetDevice() {
              const deviceNameForPrompt = currentDeviceName();
              const accepted = await promptBoundaryDialogChoice('forgetDevice', { deviceName: deviceNameForPrompt });
              if (accepted !== 'confirm') return;
              await disconnectDevice();
            }

            async function disconnectDevice() {
              bumpSessionMutationGeneration();
              clearPreview();
              renderDeviceList(await requestJson('/api/device/disconnect', { method: 'POST' }));
              setDeviceUiState(DeviceUiState.NONE);
              render();
              stopHeartbeatPolling();
              applyConnectionStatus(welcomeConnectionStatus());
            }
//#endregion devices.js

//#region draftApiAdapter.js
// @requires draftPorts.js, draftWorkspace.js
// draftApiAdapter.js - explicit-session HTTP adapter for DraftWorkspace use cases.

function draftItemToAnnotationDraftDto(item, options = {}) {
  const rawComment = String(item.comment || '');
  const fallbackComment = String(item.label || '').trim() || (item.targetType === 'node' ? 'Component target' : 'Custom area');
  return {
    draftItemId: item.draftItemId || null,
    targetType: item.targetType,
    bounds: item.bounds,
    nodeUid: item.nodeUid,
    label: String(item.label || '').trim() || null,
    severity: item.severity || 'med',
    status: String(item.status || 'open').replace('-', '_'),
    comment: options.allowFallbackComments ? (rawComment.trim() || fallbackComment) : rawComment,
  };
}

function createDraftApiError({ error, message, action, status }) {
  const typed = new Error(message || error || ('HTTP ' + status));
  typed.code = error || 'http_error';
  typed.action = action || null;
  typed.status = status || null;
  return typed;
}

function isValidSelectionBounds(bounds) {
  return Number.isFinite(bounds?.left) &&
    Number.isFinite(bounds?.top) &&
    Number.isFinite(bounds?.right) &&
    Number.isFinite(bounds?.bottom) &&
    bounds.right > bounds.left &&
    bounds.bottom > bounds.top;
}

function requireValidSelectionBounds(item) {
  if (item?.targetType !== 'area' && item?.targetType !== 'node') return;
  if (isValidSelectionBounds(item.bounds)) return;
  throw createDraftApiError({
    error: 'invalid_selection_bounds',
    message: 'Selection bounds are invalid for draft item: ' + (item?.draftItemId || 'unknown'),
    action: 'recapture_or_select_area',
  });
}

function screenHasNodeUid(screen, nodeUid) {
  if (!screen || !nodeUid) return false;
  return (screen.roots || []).some((root) => {
    return (root?.mergedNodes || []).some((node) => node?.uid === nodeUid) ||
      (root?.unmergedNodes || []).some((node) => node?.uid === nodeUid);
  });
}

function normalizeDraftItemForScreen(item, screen) {
  if (item?.targetType !== 'node' || !item.nodeUid || !screen || screenHasNodeUid(screen, item.nodeUid)) {
    return item;
  }
  return {
    ...item,
    targetType: 'area',
    nodeUid: undefined,
  };
}

function buildDraftWorkspaceSaveRequest(workspace, options = {}) {
  const context = workspace?.context || {};
  if (!context.sessionId) throw new Error('Draft save requires sessionId');
  if (!context.previewId) throw new Error('Draft save requires previewId');
  requireDraftContext(workspace);
  return {
    sessionId: context.sessionId,
    previewId: context.previewId,
    workspaceId: workspace.workspaceId || null,
    screen: workspace.screen || null,
    items: (workspace.items || [])
      .filter((item) => options.allowBlankComments || options.allowFallbackComments || String(item.comment || '').trim())
      .map((item) => {
        requireValidSelectionBounds(item);
        return item;
      })
      .map((item) => normalizeDraftItemForScreen(item, workspace.screen))
      .map((item) => draftItemToAnnotationDraftDto(item, options)),
    frozenFingerprint: context.screenFingerprint,
    forceMismatchOverride: Boolean(options.forceMismatchOverride),
  };
}

function createDraftApiHeaders(consoleToken) {
  const headers = new Headers({ 'Content-Type': 'application/json' });
  if (consoleToken) headers.set('X-FixThis-Console-Token', consoleToken);
  return headers;
}

function createDraftApiAdapter({ fetchImpl = fetch, consoleToken = null } = {}) {
  async function readErrorBody(response) {
    const parsed = await response.json?.().catch(() => null);
    if (parsed && typeof parsed === 'object') return parsed;
    const message = await response.text?.().catch(() => '') || 'HTTP ' + response.status;
    return { error: 'http_error', message };
  }

  async function requestJson(path, body, init = {}) {
    const headers = createDraftApiHeaders(consoleToken);
    if (init.ifMatch) headers.set('If-Match', init.ifMatch);
    const response = await fetchImpl(path, {
      method: 'POST',
      headers,
      body: JSON.stringify(body),
    });
    if (!response.ok) {
      if (response.status === 409) {
        const conflict = await response.json().catch(() => ({}));
        return { conflict };
      }
      if (response.status === 412) {
        const staleDraft = await response.json().catch(() => ({}));
        return { staleDraft, etag: response.headers?.get?.('ETag') || null };
      }
      const errorBody = await readErrorBody(response);
      throw createDraftApiError({ ...errorBody, status: response.status });
    }
    return await response.json();
  }

  return {
    saveDraftWorkspace: (request, init) => requestJson('/api/items/batch', request, init),
    saveToMcp: (sessionId, itemIds) => requestJson('/api/agent-handoffs', { sessionId, itemIds }),
    handoffPreview: async (sessionId, itemIds) => {
      const response = await fetchImpl('/api/sessions/' + encodeURIComponent(sessionId) + '/handoff-preview', {
        method: 'POST',
        headers: createDraftApiHeaders(consoleToken),
        body: JSON.stringify({ itemIds }),
      });
      if (!response.ok) throw new Error(await response.text?.() || 'HTTP ' + response.status);
      return await response.text();
    },
    markHandedOff: (sessionId, itemIds) =>
      requestJson('/api/sessions/' + encodeURIComponent(sessionId) + '/items/mark-handed-off', { itemIds }),
  };
}

// Stale-draft (HTTP 412) resolver. Spec S1.4.5: open `staleDraftConflict`
// boundary dialog with three buttons. Result object shape:
//   { action: 'overwrite', retry: () => Promise<saveResult> }
//   { action: 'useServer', serverDraft: <SessionDto> }
//   { action: 'cancel' }
async function resolveStaleDraftConflict({ adapter, request, staleDraft, prompt, render }) {
  if (typeof render === 'function') render('staleDraftConflict', { readiness: staleDraft?.readiness || null });
  const choice = await prompt();
  if (choice === 'overwrite') {
    return { action: 'overwrite', retry: () => adapter.saveDraftWorkspace(request, { ifMatch: '*' }) };
  }
  if (choice === 'useServer') {
    return { action: 'useServer', serverDraft: staleDraft?.serverDraft || null };
  }
  return { action: 'cancel' };
}
//#endregion draftApiAdapter.js

//#region sessions-polling.js
// @requires state.js, api.js
            // sessions-polling.js — FALLBACK-ONLY session polling. The timer is
            // armed only while SSE is unavailable (shouldUseSessionFallbackPolling()).
            // Under a healthy EventSource session no timer is created and no
            // /api/sessions poll fetch occurs (asserted by
            // scripts/console-browser-reliability.mjs). Explicit recovery
            // (reconnect, manual refresh) re-invokes startSessionsPolling().
            const SessionsPollIntervalMs = 2000;

            // sessionsPollingTimer is the setInterval handle; lives in this
            // closure (no longer at module scope) so polling-owned timer
            // state never leaks into state.js.
            let sessionsPollingTimer = null;

            function setSessionsPollingPaused(paused) {
              if (connectionUseCases.getState().sessionsPollingPaused === paused) return;
              connectionUseCases.setSessionsPollingPaused(paused);
              // Mirror into the polling FSM via visibility-style transitions
              // so the lifecycle stays consistent.
              if (paused) pollingUseCases.visibilityHidden();
              else pollingUseCases.visibilityVisible();
              // Re-render the connection card to surface the change.
              const connectionState = connectionUseCases.getState();
              if (connectionState.current) renderConnection(connectionState.current);
            }

            function shouldPollSessions() {
              return shouldUseSessionFallbackPolling() &&
                !document.hidden &&
                pollingUseCases.getState().pendingMutationCount === 0 &&
                !isEditingAnnotation();
            }

            function isEditingAnnotation() {
              const active = document.activeElement;
              if (!active) return false;
              return active.id === 'annotationCommentInput' || active.id === 'annotationLabelInput';
            }

            function startSessionsPolling() {
              stopSessionsPolling();
              // Fallback-only: do not arm the polling timer while SSE is healthy.
              // The SSE-drop path re-invokes startSessionsPolling() to resume.
              if (!shouldUseSessionFallbackPolling()) return;
              pollingUseCases.startSessionsPolling();
              sessionsPollingTimer = setInterval(() => {
                if (shouldPollSessions()) pollSessionsTick().catch(() => {
                  // pollSessionsTick already handles its own failures; this catch is defensive.
                });
              }, SessionsPollIntervalMs);
            }

            function stopSessionsPolling() {
              if (sessionsPollingTimer) clearInterval(sessionsPollingTimer);
              sessionsPollingTimer = null;
              pollingUseCases.stopSessionsPolling();
            }

            function isSessionsPollingArmed() {
              return sessionsPollingTimer !== null;
            }

            // pollSessionsTick delegates the HTTP + FSM bookkeeping to
            // pollingUseCases.pollSessionsTick (api.sessions performs the
            // actual fetches and side-effects; the use case dispatches
            // TICK_OK / TICK_FAILED). At the threshold, the FSM transitions
            // to POLLING_BACKOFF; this wrapper observes that transition and
            // mirrors it into the connection FSM via setSessionsPollingPaused
            // so legacy UI continues to surface the pause.
            async function pollSessionsTick() {
              try {
                await pollingUseCases.pollSessionsTick();
              } catch (err) {
                if (pollingUseCases.getState().lifecycle === PollingLifecycle.POLLING_BACKOFF) {
                  setSessionsPollingPaused(true);
                  stopSessionsPolling();
                }
                // Swallow error silently while in backoff window — no toast for transient failures.
                return;
              }
              // success path: ensure not paused (drain any stale paused projection)
              if (connectionUseCases.getState().sessionsPollingPaused) {
                setSessionsPollingPaused(false);
              }
            }
//#endregion sessions-polling.js

//#region serverBuildChip.js
// @requires (none)
let serverBuildChipNode = null;

function renderServerBuildChip(node) {
  const cfg = (typeof window !== 'undefined' && window.FixThisConsoleConfig) || {};
  node.dataset.state = 'connected';
  node.textContent = formatChipText('connected', cfg.buildHash);
}

function updateServerBuildChipState(node, { state, buildHash } = {}) {
  if (!node) return;
  if (state) node.dataset.state = state;
  const cfg = (typeof window !== 'undefined' && window.FixThisConsoleConfig) || {};
  const hash = buildHash ?? cfg.buildHash;
  node.textContent = formatChipText(node.dataset.state, hash);
}

function formatChipText(state, buildHash) {
  if (state === 'reconnecting') return 'reconnecting…';
  if (state === 'connected' && buildHash) return `connected · build sha=${buildHash}`;
  if (state === 'connected') return 'connected';
  return state || '';
}

function mountServerBuildChip() {
  if (typeof document === 'undefined') return null;
  if (serverBuildChipNode) return serverBuildChipNode;
  const host = document.querySelector('.studio-context');
  if (!host) return null;
  const node = document.createElement('span');
  node.id = 'fixthis-server-build-chip';
  host.appendChild(node);
  renderServerBuildChip(node);
  serverBuildChipNode = node;
  return node;
}

function getServerBuildChipNode() {
  return serverBuildChipNode;
}
